/**
 * Returns OPD hours for a hospital by name, or a sensible default.
 * @param {string} name - Hospital name as stored in HOSPITALS array
 * @returns {{ weekday:string, saturday:string, sunday:string, note:string }}
 */
function getOpdHours(name) {
  return HOSP_OPD[name] || {
    weekday:  'Mon–Fri: Contact hospital',
    saturday: 'Sat: Contact hospital',
    sunday:   'Sun: Contact hospital',
    note:     'Call ahead to confirm OPD timings.'
  };
}

// ==========================================
// CATEGORY → SPECIALTY MAPPING (all 20 CATS)
// ==========================================
/**
 * Maps every CATS key to the matching SPEC_CONFIG specialty key(s).
 * Used for detecting which specialist a user should see based on a
 * treatment category query.
 */
const CAT_SPECIALTY_MAP = {
  cardiac:    { spec:'cardiac',   specialist:'Cardiologist',         keywords:['heart','cardiac','chest pain','angina','palpitation','arrhythmia','bypass','cath lab'] },
  respiratory:{ spec:'general',   specialist:'Pulmonologist',        keywords:['breathing','lungs','asthma','copd','pneumonia','respiratory','inhaler','bronchitis','oxygen'] },
  trauma:     { spec:'trauma',    specialist:'Emergency Surgeon / Trauma Surgeon', keywords:['accident','fracture','injury','crash','head injury','trauma','wound','bleed'] },
  burns:      { spec:'burns',     specialist:'Burns Specialist / Plastic Surgeon', keywords:['burn','scald','fire','chemical burn','electrical burn','thermal'] },
  neuro:      { spec:'neuro',     specialist:'Neurologist / Neurosurgeon',         keywords:['brain','stroke','seizure','convulsion','paralysis','neuro','spine','headache','epilepsy','unconscious'] },
  allergy:    { spec:'general',   specialist:'Allergist / Immunologist',           keywords:['allergy','anaphylaxis','hives','rash','epipen','allergic reaction','urticaria'] },
  gastro:     { spec:'general',   specialist:'Gastroenterologist',                 keywords:['stomach','gut','vomiting blood','gastro','liver','bowel','intestine','appendix','pancreatitis','ulcer','diarrhea'] },
  musculo:    { spec:'orthopedic',specialist:'Orthopaedic Surgeon / Physiotherapist', keywords:['bone','joint','muscle','fracture','sprain','dislocate','ortho','spine','back pain','knee','shoulder'] },
  peds:       { spec:'pediatric', specialist:'Paediatrician',                      keywords:['child','infant','baby','pediatric','kid','newborn','toddler','febrile','childhood'] },
  enviro:     { spec:'general',   specialist:'Emergency Physician / Intensivist',  keywords:['heatstroke','hypothermia','frostbite','drowning','lightning','altitude','dehydration','sunstroke','exposure'] },
  poisoning:  { spec:'general',   specialist:'Toxicologist / Poison Control',      keywords:['poison','overdose','swallowed','toxic','ingested','fumes','carbon monoxide','narcan','naloxone'] },
  eye:        { spec:'eye',       specialist:'Ophthalmologist / ENT Surgeon',      keywords:['eye','vision','blind','ear','nose','throat','ent','cornea','retina','hearing'] },
  skin:       { spec:'general',   specialist:'Dermatologist',                      keywords:['skin','rash','itch','derma','blister','sores','infection skin','eczema','psoriasis','hives'] },
  obstetric:  { spec:'obstetric', specialist:'Obstetrician / Gynaecologist (OB-GYN)', keywords:['pregnancy','labour','delivery','miscarriage','eclampsia','obstetric','placenta','antenatal','postnatal','ectopic','contractions'] },
  mental:     { spec:'mental',    specialist:'Psychiatrist / Clinical Psychologist', keywords:['mental','psychiatric','suicide','depression','anxiety','psychosis','mania','hallucination','panic attack','self harm','overdose intentional'] },
  dental:     { spec:'general',   specialist:'Dentist / Oral Surgeon',             keywords:['tooth','dental','gum','jaw','mouth','toothache','cavity','abscess oral','wisdom tooth'] },
  infectious: { spec:'infectious',specialist:'Infectious Disease Specialist',      keywords:['fever','dengue','malaria','cholera','typhoid','covid','infection','viral','bacterial','sepsis','outbreak','rabies'] },
  diabetic:   { spec:'diabetic',  specialist:'Endocrinologist / Diabetologist',    keywords:['diabetes','blood sugar','insulin','hypoglycaemia','hyperglycaemia','diabetic','dka','glucose'] },
  wound:      { spec:'general',   specialist:'General Surgeon / Wound Care Nurse', keywords:['wound','cut','laceration','suture','stitches','bleeding','gash','puncture','abrasion'] },
  toxicology: { spec:'general',   specialist:'Toxicologist / Clinical Pharmacologist', keywords:['toxin','venom','snake bite','scorpion','spider','poison gas','chemical exposure','drug interaction'] },
};

/**
 * Detects if the user query is asking about a specialist or hospital
 * for a particular medical category. Returns { catKey, entry } or null.
 */
function isCategorySpecialistQuery(query) {
  const q = query.toLowerCase();
  // Trigger words that indicate a specialist/hospital-finder intent
  const triggerPhrases = [
    'specialist','doctor','physician','surgeon','hospital for','best hospital',
    'which hospital','which doctor','good doctor','see a','consult a','visit a',
    'nearest','near me','opd','outpatient','appointment','book','consultant',
    'where to go','where should i go','who treats','who can treat','i need a doctor',
    'recommend a','suggest a hospital','suggest a doctor','expert'
  ];
  const hasTrigger = triggerPhrases.some(t => q.includes(t));
  if (!hasTrigger) return null;

  for (const [catKey, entry] of Object.entries(CAT_SPECIALTY_MAP)) {
    for (const kw of entry.keywords) {
      if (q.includes(kw)) return { catKey, entry };
    }
  }
  return null;
}

// ==========================================
// SOUND SYSTEM 🔊
// ==========================================
let _audioCtx = null;
function getAudioCtx() {
  if (!_audioCtx) _audioCtx = new (window.AudioContext || window.webkitAudioContext)();
  return _audioCtx;
}
function playTone(freq, duration, type='sine', vol=0.1) {
  try {
    const audioCtx = getAudioCtx();
    const osc = audioCtx.createOscillator();
    const gain = audioCtx.createGain();
    osc.connect(gain); gain.connect(audioCtx.destination);
    osc.frequency.value = freq; osc.type = type;
    gain.gain.setValueAtTime(vol, audioCtx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.0001, audioCtx.currentTime + duration);
    osc.start(); osc.stop(audioCtx.currentTime + duration);
  } catch(e) {}
}

function soundClick() { playTone(880, .08, 'sine', .06); }
function soundSuccess() { [523, 659, 784].forEach((f, i) => setTimeout(() => playTone(f, .15, 'sine', .08), i*80)); }
function soundOpen() {
  // Rising two-tone chime: warm and inviting
  playTone(440, .10, 'sine', .05);
  setTimeout(() => playTone(660, .18, 'sine', .07), 70);
  setTimeout(() => playTone(880, .14, 'sine', .04), 150);
}
function soundClose() {
  // Descending soft tone: clear and unobtrusive
  playTone(660, .10, 'sine', .06);
  setTimeout(() => playTone(440, .14, 'sine', .04), 70);
}
function soundError() {
  // Low dissonant double-tap
  playTone(220, .12, 'square', .04);
  setTimeout(() => playTone(196, .18, 'square', .03), 100);
}
function soundToast(type) {
  if (type === 'success') { playTone(784, .10, 'sine', .05); setTimeout(() => playTone(1047, .14, 'sine', .04), 90); }
  else if (type === 'error') { soundError(); }
  else { playTone(600, .08, 'sine', .04); }
}

// ==========================================
// TOAST NOTIFICATIONS 🔔
// ==========================================
function toast(msg, type = 'info', duration = 3000) {
  const wrap = document.getElementById('toasts');
  if(!wrap) return;
  soundToast(type);
  const t = document.createElement('div');
  t.className = `toast ${type}`;
  const icon = type === 'success' ? 'fa-check-circle' : type === 'error' ? 'fa-circle-xmark' : 'fa-circle-info';
  const color = type === 'success' ? 'var(--green)' : type === 'error' ? 'var(--red)' : 'var(--cyan)';
  t.innerHTML = `<i class="fas ${icon}" style="color:${color}"></i>${msg}`;
  // Entrance: slide in + spring scale
  t.style.cssText = 'opacity:0; transform:translateX(60px) scale(0.92);';
  wrap.appendChild(t);
  requestAnimationFrame(() => {
    requestAnimationFrame(() => {
      t.style.transition = 'opacity .32s cubic-bezier(.22,.68,0,1.2), transform .38s cubic-bezier(.22,.68,0,1.2)';
      t.style.opacity = '1';
      t.style.transform = 'translateX(0) scale(1)';
    });
  });
  // Exit: slide out + fade
  setTimeout(() => {
    t.style.transition = 'opacity .28s ease, transform .28s cubic-bezier(.4,0,.6,1)';
    t.style.opacity = '0';
    t.style.transform = 'translateX(60px) scale(0.88)';
    setTimeout(() => t.remove(), 300);
  }, duration);
}

// ==========================================
// CANVAS ANIMATION — Modern Medical Ambient
// ==========================================
(function () {
  const canvas = document.getElementById('canvas');
  if (!canvas) return;
  const ctx = canvas.getContext('2d');

  let W = canvas.width  = window.innerWidth;
  let H = canvas.height = window.innerHeight;
  window.addEventListener('resize', () => {
    W = canvas.width  = window.innerWidth;
    H = canvas.height = window.innerHeight;
    buildOrbs();
  });

  const light = () => document.body.classList.contains('light');

  // ── Palette ──────────────────────────────
  // Each color fn returns an rgba string, theme-aware
  const PAL = {
    green:  (a) => light() ? `rgba(0,168,84,${a})`   : `rgba(0,230,118,${a})`,
    red:    (a) => light() ? `rgba(200,20,60,${a})`   : `rgba(255,45,85,${a})`,
    blue:   (a) => light() ? `rgba(2,132,199,${a})`   : `rgba(56,189,248,${a})`,
    violet: (a) => light() ? `rgba(109,40,217,${a})`  : `rgba(167,139,250,${a})`,
    teal:   (a) => light() ? `rgba(15,118,110,${a})`  : `rgba(45,212,191,${a})`,
  };
  const COLORS = [PAL.green, PAL.red, PAL.blue, PAL.violet, PAL.teal];

  let t = 0;

  // ════════════════════════════════════════
  // 1.  AURORA GRADIENT ORBS
  //     Large slow-drifting luminous blobs
  // ════════════════════════════════════════
  let ORBS = [];
  function buildOrbs() {
    ORBS = [
      { cx: W * 0.15, cy: H * 0.25, r: Math.min(W, H) * 0.38, color: PAL.green,  speedX: 0.12, speedY: 0.07, phase: 0    },
      { cx: W * 0.80, cy: H * 0.15, r: Math.min(W, H) * 0.32, color: PAL.blue,   speedX:-0.09, speedY: 0.11, phase: 1.8  },
      { cx: W * 0.60, cy: H * 0.75, r: Math.min(W, H) * 0.35, color: PAL.violet, speedX: 0.07, speedY:-0.08, phase: 3.4  },
      { cx: W * 0.30, cy: H * 0.80, r: Math.min(W, H) * 0.28, color: PAL.red,    speedX:-0.11, speedY:-0.06, phase: 5.1  },
      { cx: W * 0.90, cy: H * 0.55, r: Math.min(W, H) * 0.22, color: PAL.teal,   speedX: 0.08, speedY: 0.09, phase: 2.3  },
    ];
  }
  buildOrbs();

  function drawOrbs() {
    ORBS.forEach(o => {
      const nx = o.cx + Math.sin(t * o.speedX + o.phase) * W * 0.12;
      const ny = o.cy + Math.cos(t * o.speedY + o.phase) * H * 0.10;
      const alpha = light() ? 0.13 : 0.18;
      const grad = ctx.createRadialGradient(nx, ny, 0, nx, ny, o.r);
      grad.addColorStop(0,   o.color(alpha));
      grad.addColorStop(0.5, o.color(alpha * 0.4));
      grad.addColorStop(1,   o.color(0));
      ctx.beginPath();
      ctx.arc(nx, ny, o.r, 0, Math.PI * 2);
      ctx.fillStyle = grad;
      ctx.fill();
    });
  }

  // ════════════════════════════════════════
  // 2.  LIVE ECG TRACER
  //     Single horizontal line with a
  //     bright glowing tracer dot riding it
  // ════════════════════════════════════════
  const ECG = {
    y: H * 0.5,
    speed: 90,      // px per second
    seg: 180,       // pattern repeat width px
    amp: 32,
    trailLen: 260,  // px of history to keep
    history: [],    // {x, y}[]
  };

  function ecgY(nx) {
    // nx = position within one ECG segment [0..seg)
    const s = ECG.seg;
    if (nx < s * 0.15) return 0;
    if (nx < s * 0.22) return Math.sin((nx - s*0.15)/(s*0.07) * Math.PI) * ECG.amp * 0.18; // P
    if (nx < s * 0.35) return 0;
    if (nx < s * 0.38) return -ECG.amp * 0.12;   // Q
    if (nx < s * 0.42) return  ECG.amp;            // R peak
    if (nx < s * 0.46) return -ECG.amp * 0.28;   // S
    if (nx < s * 0.62) return Math.sin((nx - s*0.46)/(s*0.16) * Math.PI) * ECG.amp * 0.22; // T
    return 0;
  }

  function drawECG() {
    // Update tracer position
    const tracerX = (t * ECG.speed) % W;
    const segPos  = (t * ECG.speed) % ECG.seg;
    const tracerY = ECG.y - ecgY(segPos);
    ECG.history.push({ x: tracerX, y: tracerY });

    // Trim history to trailLen
    while (ECG.history.length > 1) {
      const oldest = ECG.history[0];
      const dx = tracerX - oldest.x;
      // handle wrap-around
      const dist = dx < 0 ? dx + W : dx;
      if (dist > ECG.trailLen) ECG.history.shift();
      else break;
    }

    if (ECG.history.length < 2) return;

    // Draw fading trail
    for (let i = 1; i < ECG.history.length; i++) {
      const prev = ECG.history[i - 1];
      const curr = ECG.history[i];
      // Skip over wrap-around gaps
      if (Math.abs(curr.x - prev.x) > ECG.seg) continue;
      const prog = i / ECG.history.length;
      const lineAlpha = prog * prog * (light() ? 0.55 : 0.70);
      ctx.beginPath();
      ctx.moveTo(prev.x, prev.y);
      ctx.lineTo(curr.x, curr.y);
      ctx.strokeStyle = PAL.green(lineAlpha);
      ctx.lineWidth = 1.2 + prog * 0.8;
      ctx.lineCap = 'round';
      ctx.stroke();
    }

    // Glowing tracer dot
    const glowR = 18;
    const dotGrad = ctx.createRadialGradient(tracerX, tracerY, 0, tracerX, tracerY, glowR);
    dotGrad.addColorStop(0,   PAL.green(light() ? 0.90 : 1.0));
    dotGrad.addColorStop(0.3, PAL.green(light() ? 0.35 : 0.50));
    dotGrad.addColorStop(1,   PAL.green(0));
    ctx.beginPath();
    ctx.arc(tracerX, tracerY, glowR, 0, Math.PI * 2);
    ctx.fillStyle = dotGrad;
    ctx.fill();

    // Bright core dot
    ctx.beginPath();
    ctx.arc(tracerX, tracerY, 2.5, 0, Math.PI * 2);
    ctx.fillStyle = PAL.green(1);
    ctx.fill();

    // Flat baseline (behind tracer)
    ctx.beginPath();
    ctx.moveTo(tracerX + 4, ECG.y);
    ctx.lineTo(W, ECG.y);
    ctx.strokeStyle = PAL.green(light() ? 0.06 : 0.08);
    ctx.lineWidth = 0.8;
    ctx.stroke();
  }

  // ════════════════════════════════════════
  // 3.  DNA HELIX RIBBONS  (2 sides)
  //     Smooth bezier-based ribbon strands
  // ════════════════════════════════════════
  const HELIXES = [
    { cx: 60,  c1: PAL.green,  c2: PAL.teal,   speed: 0.35, scale: 1.0, dir: 1  },
    { cx: -60, c1: PAL.violet, c2: PAL.blue,   speed: 0.28, scale: 0.9, dir:-1  },
  ];

  function drawHelix() {
    HELIXES.forEach(h => {
      const cx = h.dir === 1 ? h.cx : W + h.cx;
      const period = 130;
      const halfW  = 22 * h.scale;
      const step   = 4;

      // Draw strand 1
      ctx.beginPath();
      let first = true;
      for (let y = -10; y <= H + 10; y += step) {
        const phase = (y + t * h.speed * 100) / period * Math.PI * 2;
        const x = cx + Math.sin(phase) * halfW;
        const prog = Math.sin((y / H) * Math.PI);
        if (first) { ctx.moveTo(x, y); first = false; }
        else ctx.lineTo(x, y);
      }
      const g1 = ctx.createLinearGradient(0, 0, 0, H);
      g1.addColorStop(0,   h.c1(0));
      g1.addColorStop(0.2, h.c1(light() ? 0.20 : 0.30));
      g1.addColorStop(0.5, h.c1(light() ? 0.28 : 0.40));
      g1.addColorStop(0.8, h.c1(light() ? 0.20 : 0.30));
      g1.addColorStop(1,   h.c1(0));
      ctx.strokeStyle = g1;
      ctx.lineWidth = 1.5;
      ctx.stroke();

      // Draw strand 2
      ctx.beginPath();
      first = true;
      for (let y = -10; y <= H + 10; y += step) {
        const phase = (y + t * h.speed * 100) / period * Math.PI * 2;
        const x = cx + Math.sin(phase + Math.PI) * halfW;
        if (first) { ctx.moveTo(x, y); first = false; }
        else ctx.lineTo(x, y);
      }
      const g2 = ctx.createLinearGradient(0, 0, 0, H);
      g2.addColorStop(0,   h.c2(0));
      g2.addColorStop(0.2, h.c2(light() ? 0.15 : 0.25));
      g2.addColorStop(0.5, h.c2(light() ? 0.22 : 0.35));
      g2.addColorStop(0.8, h.c2(light() ? 0.15 : 0.25));
      g2.addColorStop(1,   h.c2(0));
      ctx.strokeStyle = g2;
      ctx.lineWidth = 1.5;
      ctx.stroke();

      // Rungs
      for (let y = -10; y <= H + 10; y += 26) {
        const phase = (y + t * h.speed * 100) / period * Math.PI * 2;
        const x1 = cx + Math.sin(phase) * halfW;
        const x2 = cx + Math.sin(phase + Math.PI) * halfW;
        const fadeA = Math.sin((y / H) * Math.PI);
        const rungA = fadeA * (light() ? 0.12 : 0.18);
        const rg = ctx.createLinearGradient(x1, y, x2, y);
        rg.addColorStop(0, h.c1(rungA));
        rg.addColorStop(1, h.c2(rungA));
        ctx.beginPath();
        ctx.moveTo(x1, y);
        ctx.lineTo(x2, y);
        ctx.strokeStyle = rg;
        ctx.lineWidth = 1;
        ctx.stroke();

        // Rung endpoints dot
        [x1, x2].forEach((xd, di) => {
          const dc = di === 0 ? h.c1 : h.c2;
          ctx.beginPath();
          ctx.arc(xd, y, 2 * h.scale, 0, Math.PI * 2);
          ctx.fillStyle = dc(rungA * 2.5);
          ctx.fill();
        });
      }
    });
  }

  // ════════════════════════════════════════
  // 4.  FLOATING PARTICLES
  //     Small depth-layered dots with soft
  //     connection mesh
  // ════════════════════════════════════════
  const PARTICLES = [];
  const P_COUNT = 70;
  for (let i = 0; i < P_COUNT; i++) {
    const depth = Math.random(); // 0=far, 1=near
    PARTICLES.push({
      x: Math.random() * window.innerWidth,
      y: Math.random() * window.innerHeight,
      r: 0.6 + depth * 2.0,
      vx: (Math.random() - 0.5) * (0.08 + depth * 0.18),
      vy: (Math.random() - 0.5) * (0.08 + depth * 0.18),
      phase: Math.random() * Math.PI * 2,
      pulse: 0.004 + Math.random() * 0.008,
      depth,
      color: COLORS[Math.floor(Math.random() * COLORS.length)],
    });
  }

  function drawParticles() {
    // Move
    PARTICLES.forEach(p => {
      p.x += p.vx;
      p.y += p.vy;
      p.phase += p.pulse;
      if (p.x < -5) p.x = W + 5;
      if (p.x > W + 5) p.x = -5;
      if (p.y < -5) p.y = H + 5;
      if (p.y > H + 5) p.y = -5;
    });

    // Connections first (behind dots)
    const connectDist = 110;
    for (let i = 0; i < PARTICLES.length; i++) {
      const a = PARTICLES[i];
      for (let j = i + 1; j < PARTICLES.length; j++) {
        const b = PARTICLES[j];
        const dx = a.x - b.x, dy = a.y - b.y;
        const d = Math.sqrt(dx * dx + dy * dy);
        if (d < connectDist) {
          const alpha = (1 - d / connectDist) * 0.055 * ((a.depth + b.depth) / 2 + 0.3);
          ctx.beginPath();
          ctx.moveTo(a.x, a.y);
          ctx.lineTo(b.x, b.y);
          ctx.strokeStyle = PAL.green(alpha);
          ctx.lineWidth = 0.5;
          ctx.stroke();
        }
      }
    }

    // Dots
    PARTICLES.forEach(p => {
      const baseAlpha = 0.15 + p.depth * 0.35;
      const alpha = baseAlpha + Math.sin(p.phase) * 0.10;
      // Halo
      const gr = ctx.createRadialGradient(p.x, p.y, 0, p.x, p.y, p.r * 5);
      gr.addColorStop(0, p.color(alpha * 0.5));
      gr.addColorStop(1, p.color(0));
      ctx.beginPath();
      ctx.arc(p.x, p.y, p.r * 5, 0, Math.PI * 2);
      ctx.fillStyle = gr;
      ctx.fill();
      // Core
      ctx.beginPath();
      ctx.arc(p.x, p.y, p.r, 0, Math.PI * 2);
      ctx.fillStyle = p.color(alpha);
      ctx.fill();
    });
  }

  // ════════════════════════════════════════
  // 5.  HEARTBEAT PULSE RINGS
  //     Concentric rings emanating from
  //     two focal points, precisely timed
  // ════════════════════════════════════════
  const PULSE_RINGS = [];
  let lastPulse1 = 0, lastPulse2 = 0;

  function spawnRing(x, y, color, maxR) {
    PULSE_RINGS.push({ x, y, r: 2, maxR, alpha: 0.5, color, lineW: 1.8 });
    // Second inner ring with slight delay
    setTimeout(() => {
      PULSE_RINGS.push({ x, y, r: 2, maxR: maxR * 0.6, alpha: 0.35, color, lineW: 1.0 });
    }, 120);
  }

  function drawPulseRings() {
    // Spawn on heartbeat rhythm (~72bpm ≈ 833ms)
    if (t - lastPulse1 > 0.83) {
      spawnRing(W * 0.22, H * 0.38, PAL.red, 160);
      lastPulse1 = t;
    }
    if (t - lastPulse2 > 1.15) {
      spawnRing(W * 0.78, H * 0.62, PAL.green, 140);
      lastPulse2 = t;
    }

    for (let i = PULSE_RINGS.length - 1; i >= 0; i--) {
      const rg = PULSE_RINGS[i];
      rg.r     += 1.4;
      rg.alpha *= 0.972;
      if (rg.alpha < 0.004 || rg.r > rg.maxR) { PULSE_RINGS.splice(i, 1); continue; }
      ctx.beginPath();
      ctx.arc(rg.x, rg.y, rg.r, 0, Math.PI * 2);
      ctx.strokeStyle = rg.color(rg.alpha);
      ctx.lineWidth = rg.lineW;
      ctx.stroke();
    }
  }

  // ════════════════════════════════════════
  // 6.  SCANNING GRID
  //     Subtle perspective grid lines that
  //     shimmer — like a medical HUD
  // ════════════════════════════════════════
  function drawGrid() {
    const cols = 12, rows = 8;
    const cw = W / cols, ch = H / rows;
    const shimA = light() ? 0.025 : 0.04;

    ctx.lineWidth = 0.5;
    // Vertical lines
    for (let c = 0; c <= cols; c++) {
      const x = c * cw;
      const shimmer = Math.sin(t * 0.4 + c * 0.5) * 0.5 + 0.5;
      ctx.beginPath();
      ctx.moveTo(x, 0);
      ctx.lineTo(x, H);
      ctx.strokeStyle = PAL.green(shimA * shimmer);
      ctx.stroke();
    }
    // Horizontal lines
    for (let r = 0; r <= rows; r++) {
      const y = r * ch;
      const shimmer = Math.sin(t * 0.3 + r * 0.7) * 0.5 + 0.5;
      ctx.beginPath();
      ctx.moveTo(0, y);
      ctx.lineTo(W, y);
      ctx.strokeStyle = PAL.green(shimA * shimmer * 0.6);
      ctx.stroke();
    }
  }

  // ════════════════════════════════════════
  // MAIN DRAW LOOP
  // ════════════════════════════════════════
  function draw() {
    ctx.clearRect(0, 0, W, H);
    t += 0.016;

    drawOrbs();       // layer 1: big ambient blobs
    drawGrid();       // layer 2: HUD grid
    drawHelix();      // layer 3: DNA ribbons (sides)
    drawParticles();  // layer 4: particle mesh
    drawPulseRings(); // layer 5: heartbeat rings
    drawECG();        // layer 6: ECG tracer (top)

    requestAnimationFrame(draw);
  }

  draw();
})();

// ==========================================
// UI RENDERING
// ==========================================
function renderCategories() {
  const grid = document.getElementById('catGrid');
  if(!grid) return;
  const counts = {};
  DB.forEach(t => counts[t.cat] = (counts[t.cat] || 0) + 1);
  Object.entries(CATS).forEach(([key, cat]) => {
    const div = document.createElement('div');
    div.className = 'cat-card';
    div.innerHTML = `
      <div class="cat-icon" style="background:${cat.bg}">
        <i class="fas ${cat.icon}" style="color:${cat.color}"></i>
      </div>
      <h3>${cat.label}</h3>
      <p>${counts[key] || 0} protocols</p>
      <span class="badge" style="background:${cat.bg};color:${cat.color}">${cat.label}</span>
    `;
    div.onclick = () => { soundClick(); filterTreatments(key); scrollToEl('#treatments'); };
    grid.appendChild(div);
  });
}

function renderFilters() {
  const row = document.getElementById('filterRow');
  if(!row) return;
  const all = document.createElement('button');
  all.className = 'filter-btn active';
  all.textContent = 'All';
  all.onclick = () => { filterTreatments('all'); setActiveFilter(all); };
  row.appendChild(all);
  
  ['critical','high','moderate','low'].forEach(sev => {
    const btn = document.createElement('button');
    btn.className = 'filter-btn';
    btn.innerHTML = `<span class="sev-badge sev-${sev}">${sev.charAt(0).toUpperCase()+sev.slice(1)}</span>`;
    btn.onclick = () => { filterBySeverity(sev); setActiveFilter(btn); };
    row.appendChild(btn);
  });
}

function setActiveFilter(el) {
  document.querySelectorAll('.filter-btn').forEach(b => b.classList.remove('active'));
  el.classList.add('active');
  soundClick();
}

function renderTreatments(items = null) {
  const grid = document.getElementById('tGrid');
  if(!grid) return;
  grid.innerHTML = '';
  shownCount = 0;
  currentDisplayed = items || DB.filter(d => currentFilter === 'all' || d.cat === currentFilter);
  
  currentDisplayed.slice(0, PAGE_SIZE).forEach(t => { grid.appendChild(createTCard(t)); shownCount++; });
  const loadBtn = document.getElementById('loadMoreBtn');
  if(loadBtn) {
    loadBtn.style.display = shownCount >= currentDisplayed.length ? 'none' : 'inline-block';
  }
}

function createTCard(t) {
  const cat = CATS[t.cat];
  const isBookmarked = bookmarks.includes(t.id);
  const div = document.createElement('div');
  div.className = 't-card';
  div.innerHTML = `
    <div class="t-card-top">
      <div class="t-icon" style="background:${cat.bg}">
        <i class="fas ${t.icon}" style="color:${cat.color}"></i>
      </div>
      <div style="flex:1">
        <h4>${t.title}</h4>
        <div class="t-cat">${cat.label}</div>
      </div>
      <div style="display:flex;flex-direction:column;gap:.3rem;align-items:flex-end">
        <span class="sev-badge sev-${t.sev}">${t.sev}</span>
        <button onclick="event.stopPropagation();toggleBookmark('${t.id}',this)" style="background:none;border:none;cursor:pointer;color:${isBookmarked ? 'var(--amber)' : 'var(--text3)'}">
          <i class="fas fa-bookmark"></i>
        </button>
      </div>
    </div>
    <div class="t-warn"><i class="fas fa-triangle-exclamation"></i> ${t.warn.substring(0,60)}…</div>
  `;
  div.onclick = () => openTreatment(t.id);
  return div;
}

function loadMoreTreatments() {
  soundClick();
  const grid = document.getElementById('tGrid');
  const btn = document.getElementById('loadMoreBtn');
  const remaining = currentDisplayed || (currentFilter === 'all' ? DB : DB.filter(t => t.cat === currentFilter));
  const nextBatch = remaining.slice(shownCount, shownCount + PAGE_SIZE);
  
  nextBatch.forEach(t => { grid.appendChild(createTCard(t)); shownCount++; });
  if(shownCount >= remaining.length && btn) btn.style.display = 'none';
}

function filterTreatments(cat) {
  currentFilter = cat;
  renderTreatments(cat === 'all' ? DB : DB.filter(t => t.cat === cat));
}

function filterBySeverity(sev) {
  currentFilter = 'all';
  renderTreatments(DB.filter(t => t.sev === sev));
}

// ── Fisher-Yates shuffle ──
function shuffleArray(arr) {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

// Active shuffled deck (re-created each call to shuffleFlashcards)
let _fcDeck = [];

function shuffleFlashcards() {
  soundClick();
  const row = document.getElementById('fcRow');
  if (!row) return;

  // Spin the shuffle button icon
  const btn = document.getElementById('fcShuffleBtn');
  if (btn) {
    btn.classList.add('spinning');
    btn.disabled = true;
    setTimeout(() => { btn.classList.remove('spinning'); btn.disabled = false; }, 350);
  }

  // Fade-out all current cards simultaneously (no per-card stagger)
  const cards = Array.from(row.querySelectorAll('.flashcard'));
  cards.forEach(c => {
    c.style.transition = 'opacity .15s ease, transform .15s ease';
    c.style.opacity = '0';
    c.style.transform = 'scale(0.88) translateY(10px)';
  });

  setTimeout(() => {
    // Remove old cards
    row.querySelectorAll('.flashcard').forEach(c => c.remove());
    // New shuffled deck
    _fcDeck = shuffleArray(FLASHCARDS);
    // Render new cards
    renderFCCards(row);
    // Reset scroll
    row.scrollLeft = 0;
    // Trigger counter update
    row.dispatchEvent(new Event('scroll'));
  }, 200);
}

function renderFCCards(row) {
  const CAT_COLORS = {
    cardiac:'#ff2d55', respiratory:'#00e676', trauma:'#ffb300', burns:'#ff7043',
    neuro:'#a855f7', allergy:'#f59e0b', gastro:'#10b981', musculo:'#3b82f6',
    peds:'#ec4899', enviro:'#22c55e', poisoning:'#8b5cf6', eye:'#06b6d4',
    skin:'#f97316', obstetric:'#db2777', mental:'#6366f1', dental:'#64748b',
    infectious:'#ef4444', diabetic:'#0ea5e9', wound:'#dc2626', toxicology:'#7c3aed',
  };

  _fcDeck.forEach((fc, idx) => {
    const div = document.createElement('div');
    div.className = 'flashcard';
    div.style.cssText = 'flex-shrink:0; position:relative; opacity:0; transform:scale(0.88) translateY(12px);';

    const accentColor = CAT_COLORS[fc.cat] || 'var(--cyan)';

    div.innerHTML = `
      <div class="tilt-shine"></div>
      <div class="fc-inner">
        <div class="fc-front">
          <div class="fc-q">${fc.q}</div>
          <div class="fc-hint"><i class="fas fa-hand-pointer"></i> Tap to reveal answer</div>
        </div>
        <div class="fc-back"><div class="fc-a">${fc.a}</div></div>
      </div>
    `;

    // Stagger entrance animation
    setTimeout(() => {
      div.style.transition = 'opacity .28s cubic-bezier(.22,.68,0,1.2), transform .3s cubic-bezier(.22,.68,0,1.2)';
      div.style.opacity = '1';
      div.style.transform = 'scale(1) translateY(0)';
    }, idx * 8 + 20);

    // ── 3D tilt on mouse move ──
    const TILT = 14;
    div.addEventListener('mousemove', e => {
      if (div.classList.contains('flipped')) return;
      const r  = div.getBoundingClientRect();
      const x  = (e.clientX - r.left) / r.width;
      const y  = (e.clientY - r.top)  / r.height;
      const rX = (y - 0.5) * -TILT;
      const rY = (x - 0.5) *  TILT;
      div.style.transform = `perspective(700px) rotateX(${rX}deg) rotateY(${rY}deg) scale3d(1.04,1.04,1.04)`;
      div.style.setProperty('--mx', `${x * 100}%`);
      div.style.setProperty('--my', `${y * 100}%`);
    });

    div.addEventListener('mouseleave', () => {
      div.style.transform = 'perspective(700px) rotateX(0deg) rotateY(0deg) scale3d(1,1,1)';
    });

    div.onclick = () => {
      div.style.transform = 'perspective(700px) rotateX(0deg) rotateY(0deg) scale3d(1,1,1)';
      div.classList.toggle('flipped');
      soundClick();
    };

    row.appendChild(div);
  });
}

function renderFlashcards() {
  const row = document.getElementById('fcRow');
  if(!row) return;

  // ── Scroll container styles ──
  row.style.cssText = `
    display: flex;
    flex-wrap: nowrap;
    overflow-x: auto;
    overflow-y: visible;
    gap: 1rem;
    padding: 1rem 0.5rem 1.4rem;
    scroll-behavior: smooth;
    -webkit-overflow-scrolling: touch;
    scrollbar-width: thin;
    scrollbar-color: var(--cyan) transparent;
    cursor: grab;
  `;

  // ── Inject styles once ──
  if (!document.getElementById('fcScrollStyle')) {
    const style = document.createElement('style');
    style.id = 'fcScrollStyle';
    style.textContent = `
      #fcRow::-webkit-scrollbar { height: 5px; }
      #fcRow::-webkit-scrollbar-track { background: transparent; }
      #fcRow::-webkit-scrollbar-thumb { background: var(--cyan); border-radius: 99px; }
      #fcRow.grabbing { cursor: grabbing !important; }
      .fc-scroll-btn {
        position: absolute;
        top: 50%;
        transform: translateY(-50%);
        z-index: 10;
        background: var(--glass, rgba(255,255,255,0.08));
        border: 1px solid var(--glassborder, rgba(255,255,255,0.15));
        color: var(--cyan, #00e676);
        width: 36px; height: 36px;
        border-radius: 50%;
        display: flex; align-items: center; justify-content: center;
        cursor: pointer;
        transition: background 0.2s, opacity 0.2s;
        font-size: 0.85rem;
        backdrop-filter: blur(8px);
      }
      .fc-scroll-btn:hover { background: rgba(0,230,118,0.18); }
      .fc-scroll-btn.hidden { opacity: 0; pointer-events: none; }
      .fc-scroll-btn.left  { left: 0; }
      .fc-scroll-btn.right { right: 0; }
      .fc-scroll-wrap { position: relative; overflow: hidden; }
      .fc-footer {
        display: flex;
        align-items: center;
        justify-content: center;
        gap: 0.75rem;
        margin-top: 0.5rem;
      }
      .fc-counter {
        font-size: 0.72rem;
        color: var(--text3);
        letter-spacing: 0.04em;
      }
      #fcShuffleBtn {
        display: inline-flex;
        align-items: center;
        gap: 0.35rem;
        padding: 0.3rem 0.85rem;
        border-radius: 99px;
        border: 1px solid rgba(0,230,118,0.35);
        background: rgba(0,230,118,0.08);
        color: var(--cyan, #00e676);
        font-size: 0.72rem;
        font-weight: 600;
        cursor: pointer;
        transition: background .2s, transform .15s;
        letter-spacing: 0.03em;
      }
      #fcShuffleBtn:hover { background: rgba(0,230,118,0.18); }
      #fcShuffleBtn:active { transform: scale(0.95); }
      #fcShuffleBtn:disabled { opacity: 0.5; cursor: default; }
      #fcShuffleBtn .shuffle-icon {
        display: inline-block;
        transition: transform .6s cubic-bezier(.22,.68,0,1.2);
      }
      #fcShuffleBtn.spinning .shuffle-icon {
        transform: rotate(540deg);
      }
      /* ── Tilt / flip effect ── */
      .flashcard {
        transform-style: preserve-3d;
        transition: transform 0.08s ease, box-shadow 0.08s ease;
        will-change: transform;
        border-radius: 16px;
        /* overflow:hidden must NOT be set — it collapses the 3D stacking context */
      }
      .flashcard:hover {
        box-shadow: 0 16px 48px rgba(0,0,0,0.45), 0 0 24px rgba(0,230,118,0.12);
      }
      /* fc-inner is the rotating plane — it flips, not the outer card */
      .fc-inner {
        position: relative;
        width: 100%;
        height: 100%;
        transform-style: preserve-3d;
        transition: transform 0.52s cubic-bezier(.22,.68,0,1.2);
        border-radius: 16px;
      }
      /* Flip when .flipped is toggled on the parent .flashcard */
      .flashcard.flipped .fc-inner {
        transform: rotateY(180deg);
      }
      /* Both faces: hidden from the back, stacked on top of each other */
      .fc-front,
      .fc-back {
        position: absolute;
        inset: 0;
        width: 100%;
        height: 100%;
        backface-visibility: hidden;
        -webkit-backface-visibility: hidden;
        border-radius: 16px;
        overflow: hidden;
      }
      /* Back face starts rotated 180deg so it's invisible until card flips */
      .fc-back {
        transform: rotateY(180deg);
      }
      .flashcard .tilt-shine {
        position: absolute; inset: 0;
        border-radius: inherit;
        pointer-events: none;
        background: radial-gradient(circle at var(--mx,50%) var(--my,50%), rgba(255,255,255,0.12) 0%, transparent 65%);
        opacity: 0; transition: opacity 0.15s; z-index: 3;
      }
      .flashcard:hover .tilt-shine { opacity: 1; }
    `;
    document.head.appendChild(style);
  }

  // ── Wrap #fcRow (only once) ──
  const existingWrap = row.closest('.fc-scroll-wrap');
  if (!existingWrap) {
    const wrap = document.createElement('div');
    wrap.className = 'fc-scroll-wrap';
    row.parentNode.insertBefore(wrap, row);
    wrap.appendChild(row);

    // Arrow buttons
    const btnL = document.createElement('button');
    btnL.className = 'fc-scroll-btn left';
    btnL.innerHTML = '<i class="fas fa-chevron-left"></i>';
    btnL.setAttribute('aria-label', 'Scroll left');

    const btnR = document.createElement('button');
    btnR.className = 'fc-scroll-btn right';
    btnR.innerHTML = '<i class="fas fa-chevron-right"></i>';
    btnR.setAttribute('aria-label', 'Scroll right');

    wrap.appendChild(btnL);
    wrap.appendChild(btnR);

    // Footer: counter + shuffle button
    const footer = document.createElement('div');
    footer.className = 'fc-footer';
    footer.innerHTML = `
      <button id="fcShuffleBtn" onclick="shuffleFlashcards()">
        <i class="fas fa-shuffle shuffle-icon"></i> Shuffle
      </button>
    `;
    wrap.parentNode.insertBefore(footer, wrap.nextSibling);

    const SCROLL_AMT = 320;

    const updateArrows = () => {
      const atStart = row.scrollLeft <= 4;
      const atEnd   = row.scrollLeft >= row.scrollWidth - row.clientWidth - 4;
      btnL.classList.toggle('hidden', atStart);
      btnR.classList.toggle('hidden', atEnd);
    };

    btnL.onclick = () => { soundClick(); row.scrollBy({ left: -SCROLL_AMT, behavior: 'smooth' }); };
    btnR.onclick = () => { soundClick(); row.scrollBy({ left:  SCROLL_AMT, behavior: 'smooth' }); };
    row.addEventListener('scroll', updateArrows);
    window.addEventListener('resize', updateArrows);

    // ── Drag-to-scroll ──
    let isDown = false, startX, scrollStart;
    row.addEventListener('mousedown', e => {
      isDown = true; startX = e.pageX; scrollStart = row.scrollLeft;
      row.classList.add('grabbing');
    });
    document.addEventListener('mouseup',   () => { isDown = false; row.classList.remove('grabbing'); });
    document.addEventListener('mousemove', e => {
      if (!isDown) return;
      e.preventDefault();
      row.scrollLeft = scrollStart - (e.pageX - startX);
    });

    // Touch swipe
    let touchStartX = 0, touchScrollStart = 0;
    row.addEventListener('touchstart', e => { touchStartX = e.touches[0].clientX; touchScrollStart = row.scrollLeft; }, { passive: true });
    row.addEventListener('touchmove',  e => { row.scrollLeft = touchScrollStart - (e.touches[0].clientX - touchStartX); }, { passive: true });

    setTimeout(updateArrows, 50);
  }

  // ── Initial shuffle + render ──
  _fcDeck = shuffleArray(FLASHCARDS);
  renderFCCards(row);
}

// ==========================================
// SEARCH 🔍
// ==========================================
function liveSearch(query) {
  const drop = document.getElementById('searchDrop');
  if(!drop) return;
  if(!query || query.length < 2) { drop.style.display = 'none'; return; }
  const q = query.toLowerCase();
  
  const results = DB.filter(t =>
    t.title.toLowerCase().includes(q) ||
    t.tags.some(tag => tag.toLowerCase().includes(q)) ||
    CATS[t.cat].label.toLowerCase().includes(q)
  ).slice(0, 8);
  
  if(results.length === 0) { drop.style.display = 'none'; return; }
  
  drop.innerHTML = results.map(t => {
    const cat = CATS[t.cat];
    return `<div class="sd-item" onclick="openTreatment('${t.id}');document.getElementById('searchDrop').style.display='none';document.getElementById('navSearch').value=''">
      <i class="fas ${t.icon}" style="color:${cat.color};width:16px"></i>
      <span>${t.title}</span>
      <span class="sev-badge sev-${t.sev}" style="margin-left:auto">${t.sev}</span>
    </div>`;
  }).join('');
  // Animate dropdown entrance
  drop.style.display = 'block';
  drop.style.opacity = '0';
  drop.style.transform = 'translateY(-8px) scaleY(0.95)';
  drop.style.transformOrigin = 'top';
  requestAnimationFrame(() => {
    requestAnimationFrame(() => {
      drop.style.transition = 'opacity .22s ease, transform .25s cubic-bezier(.22,.68,0,1.2)';
      drop.style.opacity = '1';
      drop.style.transform = 'translateY(0) scaleY(1)';
    });
  });
}

function doSearch() {
  soundClick();
  const val = document.getElementById("navSearch").value.toLowerCase();
  if(!val) return;
  const results = DB.filter(t =>
    t.title.toLowerCase().includes(val) ||
    t.tags.join(" ").toLowerCase().includes(val) ||
    CATS[t.cat].label.toLowerCase().includes(val)
  );
  renderTreatments(results);
  const drop = document.getElementById('searchDrop');
  if(drop) drop.style.display = 'none';
  scrollToEl('#treatments');
}

// ==========================================
// MODALS & BOOKMARKS
// ==========================================
function openTreatment(id) {
  const t = DB.find(x => x.id === id);
  if(!t) return;
  const cat = CATS[t.cat];
  document.getElementById('mIcon').innerHTML = `<i class="fas ${t.icon}" style="color:${cat.color};font-size:1.4rem"></i>`;
  document.getElementById('mIcon').style.background = cat.bg;
  document.getElementById('mTitle').textContent = t.title;
  document.getElementById('mSub').innerHTML = `<span class="sev-badge sev-${t.sev}">${t.sev}</span> &nbsp;${cat.label}`;
  
  const warnClass = t.sev === 'critical' ? 'warn-box critical' : 'warn-box';
  document.getElementById('mWarn').innerHTML = `<div class="${warnClass}">${t.warn}</div>`;
  
  document.getElementById('mSteps').innerHTML = t.steps.map((s,i)=>`
    <div class="step-item">
      <div class="step-num">${i+1}</div>
      <div class="step-text">${s}</div>
    </div>
  `).join('');
  
  document.getElementById('mDoNot').innerHTML = t.donot ? `
    <div class="donot-box">
      <h3><i class="fas fa-ban" style="margin-right:.4rem"></i>Do NOT</h3>
      ${t.donot.map(d=>`<div class="donot-item"><i class="fas fa-times" style="color:var(--red);margin-top:.2rem;flex-shrink:0"></i>${d}</div>`).join('')}
    </div>
  ` : '';

  document.getElementById('mSeek').innerHTML = t.seek ? `
    <div class="seek-box">
      <h3><i class="fas fa-hospital" style="margin-right:.4rem"></i>When to Seek Emergency Care</h3>
      <p>${t.seek}</p>
    </div>
  ` : '';

  document.getElementById('mTags').innerHTML = `
    ${t.tags.map(tag=>`<span class="tag">${tag}</span>`).join('')}
  `;
  openModal('treatmentModal');
}

function toggleBookmark(id, btn) {
  soundClick();
  if(bookmarks.includes(id)) {
    bookmarks = bookmarks.filter(b => b !== id);
    if(btn) btn.style.color = 'var(--text3)';
    toast('Bookmark removed', 'info');
  } else {
    bookmarks.push(id);
    if(btn) btn.style.color = 'var(--amber)';
    toast('Treatment bookmarked!', 'success');
    soundSuccess();
  }
  localStorage.setItem('hg_bookmarks', JSON.stringify(bookmarks));
}

function openModal(id) {
  soundOpen();
  const modal = document.getElementById(id);
  if (!modal) return;
  // Cancel any in-progress close
  modal.classList.remove('modal-closing');
  modal.classList.add('open');
  if (id === 'bookmarksModal') renderBookmarks();
  document.body.style.overflow = 'hidden';
  // Find the inner box and spring it in
  const box = modal.querySelector('.modal-box, .modal-content, #hospModalBox, [class*="modal-box"]') || modal.firstElementChild;
  if (box) {
    box.style.transition = 'none';
    box.style.transform = 'translateY(48px) scale(0.94)';
    box.style.opacity = '0';
    requestAnimationFrame(() => {
      requestAnimationFrame(() => {
        box.style.transition = 'transform .42s cubic-bezier(.22,.68,0,1.2), opacity .32s cubic-bezier(.22,.68,0,1.2)';
        box.style.transform = 'translateY(0) scale(1)';
        box.style.opacity = '1';
      });
    });
  }
}

function closeModal(id) {
  soundClose();
  const modal = document.getElementById(id);
  if (!modal) return;
  const box = modal.querySelector('.modal-box, .modal-content, #hospModalBox, [class*="modal-box"]') || modal.firstElementChild;
  if (box) {
    box.style.transition = 'transform .28s cubic-bezier(.4,0,.6,1), opacity .25s ease';
    box.style.transform = 'translateY(36px) scale(0.95)';
    box.style.opacity = '0';
  }
  // Fade out backdrop
  modal.style.transition = 'opacity .28s ease';
  modal.style.opacity = '0';
  setTimeout(() => {
    modal.classList.remove('open');
    modal.style.opacity = '';
    modal.style.transition = '';
    if (box) { box.style.transform = ''; box.style.opacity = ''; box.style.transition = ''; }
    document.body.style.overflow = '';
  }, 290);
}

function renderBookmarks() {
  const list = document.getElementById('bookmarksList');
  if(!list) return;
  list.innerHTML = '';
  if(bookmarks.length === 0) {
    list.innerHTML = '<p style="color:var(--text3);text-align:center">No bookmarks yet. Click the bookmark icon on any treatment.</p>';
    return;
  }
  bookmarks.forEach(id => {
    const t = DB.find(x => x.id === id);
    if(!t) return;
    const cat = CATS[t.cat];
    const div = document.createElement('div');
    div.style.cssText = 'display:flex;align-items:center;gap:.8rem;padding:.8rem;background:var(--glass);border:1px solid var(--glassborder);border-radius:12px;cursor:pointer';
    div.innerHTML = `
      <div style="width:36px;height:36px;border-radius:8px;background:${cat.bg};display:flex;align-items:center;justify-content:center;flex-shrink:0">
        <i class="fas ${t.icon}" style="color:${cat.color}"></i>
      </div>
      <div style="flex:1"><div style="font-weight:600;font-size:.9rem">${t.title}</div><div style="font-size:.75rem;color:var(--text3)">${cat.label}</div></div>
      <span class="sev-badge sev-${t.sev}">${t.sev}</span>
    `;
    div.onclick = () => { closeModal('bookmarksModal'); openTreatment(id); };
    list.appendChild(div);
  });
}

