function appendMsg(role, text, id = null) {
  const body = document.getElementById('chatBody');
  const div = document.createElement('div');
  div.className = `msg ${role}`;
  if(id) div.id = id;
  div.innerHTML = text;
  // Slide-in animation
  div.style.opacity = '0';
  div.style.transform = role === 'bot' ? 'translateX(-16px)' : 'translateX(16px)';
  body.appendChild(div);
  requestAnimationFrame(() => {
    requestAnimationFrame(() => {
      div.style.transition = 'opacity .28s ease, transform .30s cubic-bezier(.22,.68,0,1.2)';
      div.style.opacity = '1';
      div.style.transform = 'translateX(0)';
    });
  });
  body.scrollTop = body.scrollHeight;
}

// Build a compact DB summary for the AI system prompt
function buildDBSummary() {
  return DB.map(t =>
    `[${t.id}] ${t.title} (${CATS[t.cat].label}, ${t.sev}): tags=[${t.tags.join(',')}]`
  ).join('\n');
}

// Medical synonym map for query expansion
const MEDICAL_SYNONYMS = {
  'heart attack': ['cardiac','mi','stemi','nstemi','myocardial infarction','chest pain','angina'],
  'cpr':          ['cardiac arrest','resuscitation','compressions','sca','no pulse'],
  'chok':         ['choking','heimlich','airway obstruction','foreign body','blocked airway'],
  'burn':         ['burns','scald','fire','flame','thermal','chemical burn'],
  'bleed':        ['bleeding','hemorrhage','haemorrhage','blood loss','wound','laceration','cut'],
  'seizure':      ['epilepsy','convulsion','fit','shaking','tonic clonic'],
  'allerg':       ['allergy','allergic','anaphylaxis','anaphylactic','epipen'],
  'stroke':       ['cva','brain attack','facial droop','fast test','tia','slurred speech'],
  'fracture':     ['broken','break','bone','ortho','sprain','dislocation'],
  'diabet':       ['diabetes','insulin','blood sugar','hypoglycemia','hyperglycemia','dka'],
  'snake':        ['snakebite','venom','bite','envenomation'],
  'drown':        ['drowning','submersion','water','near drowning'],
  'poison':       ['poisoning','toxic','overdose','ingestion','swallowed'],
  'head injur':   ['concussion','skull','traumatic brain','tbi','hit head'],
  'asthma':       ['bronchospasm','wheeze','breathing difficulty','inhaler','respiratory'],
  'heat':         ['heatstroke','heat exhaustion','hyperthermia','sunstroke','dehydration'],
  'shock':        ['anaphylactic shock','septic shock','hypovolemic','cardiogenic shock'],
  'eye':          ['vision','corneal','foreign body eye','chemical eye'],
  'nose':         ['nosebleed','epistaxis','nasal'],
  'fever':        ['hyperthermia','high temperature','pyrexia'],
  'bp':           ['blood pressure','hypertension','hypertensive'],
  'mi ':          ['heart attack','myocardial infarction','stemi'],
  'aed':          ['defibrillator','cardiac arrest','sca'],
};

// Expand query with synonyms for better recall
function expandQuery(q) {
  let expanded = q;
  Object.entries(MEDICAL_SYNONYMS).forEach(([key, synonyms]) => {
    if (q.includes(key)) {
      expanded += ' ' + synonyms.join(' ');
    }
    synonyms.forEach(syn => {
      if (q.includes(syn) && !expanded.includes(key)) {
        expanded += ' ' + key + ' ' + synonyms.join(' ');
      }
    });
  });
  return expanded;
}

// Score local DB matches by keyword relevance
function findLocalMatches(query) {
  const q = query.toLowerCase();
  const expanded = expandQuery(q);
  // Allow short words (>=2 chars) to catch "MI", "BP", "AED"
  const words = [...new Set(expanded.split(/\s+/).filter(w => w.length >= 2))];

  return DB.map(t => {
    let score = 0;
    const titleLower = t.title.toLowerCase();
    const stepsText  = (t.steps || []).join(' ').toLowerCase();
    const donotText  = (t.donot || []).join(' ').toLowerCase();
    const tagsText   = t.tags.join(' ').toLowerCase();
    const catLabel   = CATS[t.cat].label.toLowerCase();
    const warnText   = (t.warn || '').toLowerCase();
    const seekText   = (t.seek || '').toLowerCase();
    const fullText   = `${titleLower} ${tagsText} ${catLabel} ${warnText} ${stepsText} ${donotText} ${seekText}`;

    // Exact full-query match in title — strongest signal
    if (titleLower === q) score += 30;
    else if (titleLower.includes(q)) score += 20;
    else if (fullText.includes(q)) score += 10;

    words.forEach(w => {
      if (titleLower.includes(w))  score += 6;   // title match — most valuable
      if (tagsText.includes(w))    score += 5;   // curated tags — high signal
      if (catLabel.includes(w))    score += 3;
      if (warnText.includes(w))    score += 2;
      if (stepsText.includes(w))   score += 1;
      if (donotText.includes(w))   score += 1;
      if (seekText.includes(w))    score += 1;
    });

    return { t, score };
  })
  .filter(x => x.score > 0)
  .sort((a, b) => b.score - a.score)
  .slice(0, 5)   // top 5 for richer AI context
  .map(x => x.t);
}

// Score HOSPITALS array matches by keyword relevance
function findHospitalMatches(query) {
  const q = query.toLowerCase();
  const words = q.split(/\s+/).filter(w => w.length > 2);

  // Specialty keyword synonyms → specialty keys
  const specSynonyms = {
    heart:      'cardiac', cardio: 'cardiac', cardiac: 'cardiac',
    neuro:      'neuro',   brain: 'neuro',    neurology: 'neuro', neurosurgery: 'neuro',
    trauma:     'trauma',  accident: 'trauma', emergency: 'trauma',
    burn:       'burns',   burns: 'burns',
    obstetric:  'obstetric', maternity: 'obstetric', delivery: 'obstetric', gynae: 'obstetric',
    pediatric:  'pediatric', child: 'pediatric', children: 'pediatric', baby: 'pediatric', kids: 'pediatric',
    cancer:     'cancer',  oncology: 'cancer',
    ortho:      'orthopedic', bone: 'orthopedic', orthopedic: 'orthopedic', joint: 'orthopedic',
    mental:     'mental',  psychiatry: 'mental', psychiatric: 'mental', psychology: 'mental',
    infectious: 'infectious', dengue: 'infectious', malaria: 'infectious', cholera: 'infectious',
    transplant: 'transplant',
    general:    'general',
  };

  return HOSPITALS.map(h => {
    let score = 0;
    const searchable = (h.name + ' ' + h.address + ' ' + h.specialties.join(' ') + ' ' + (h.note||'')).toLowerCase();

    if (searchable.includes(q)) score += 8;
    words.forEach(w => {
      if (searchable.includes(w)) score += 2;
      if (h.name.toLowerCase().includes(w)) score += 4;
      const specKey = specSynonyms[w];
      if (specKey && h.specialties.includes(specKey)) score += 6;
      if (w === 'govt' || w === 'government') { if (h.type === 'govt') score += 5; }
      if (w === 'private') { if (h.type === 'pvt') score += 5; }
      if (w === '24x7' || w === 'emergency') { if (h.emergency) score += 4; }
    });
    return { h, score };
  })
  .filter(x => x.score > 0)
  .sort((a, b) => b.score - a.score)
  .slice(0, 3)
  .map(x => x.h);
}

// Detect if the query is primarily about hospitals
function isHospitalQuery(query) {
  const hospitalKeywords = [
    'hospital', 'clinic', 'centre', 'center', 'doctor', 'ward', 'icu',
    'admission', 'bed', 'specialist', 'appointment', 'where to go', 'which hospital',
    'nearby hospital', 'govt hospital', 'private hospital', 'medical college',
    'nursing home', 'dispensary', 'health centre', 'nearest hospital',
    'best hospital', 'emergency room', 'er', 'casualty', 'opd',
    'outpatient', 'inpatient', 'surgeon', 'physician', 'kolkata hospital',
    'where can i', 'where should i go', 'which clinic', 'good doctor'
  ];
  const q = query.toLowerCase();
  return hospitalKeywords.some(k => q.includes(k));
}

// Detect if query is about disease information (not first aid emergency)
function isDiseaseQuery(query) {
  const diseaseKeywords = [
    'what is', 'what are', 'symptoms of', 'causes of', 'treatment for',
    'how to treat', 'how to prevent', 'prevention', 'diagnosed', 'diagnosis', 'cure for',
    'medicine for', 'disease', 'infection', 'condition', 'disorder', 'syndrome',
    'chronic', 'spread', 'contagious', 'vaccine', 'risk factor',
    'tell me about', 'explain', 'define', 'overview of', 'information on',
    'signs of', 'effects of', 'complication', 'prognosis', 'how does',
    'why does', 'can i get', 'is it contagious', 'how long', 'recovery',
    'medication', 'drug', 'antibiotic', 'pill', 'tablet', 'prescribed',
    'test for', 'blood test', 'screening', 'checkup', 'pathology'
  ];
  const q = query.toLowerCase();
  return diseaseKeywords.some(k => q.includes(k));
}

// Build compact hospital summary for AI context
function buildHospitalContext(matches) {
  return matches.map(h => {
    const specLabels = h.specialties.map(s => SPEC_CONFIG[s]?.label || s).join(', ');
    const opd = getOpdHours(h.name);
    return `Hospital: ${h.name}
Type: ${h.type === 'govt' ? 'Government' : 'Private'}
Address: ${h.address}
Phone: ${h.phone}
Emergency 24×7: ${h.emergency ? 'Yes' : 'No'}
Beds: ${h.beds || 'N/A'}
Specialties: ${specLabels}
OPD Hours — Weekdays: ${opd.weekday} | Saturday: ${opd.saturday} | Sunday: ${opd.sunday}
OPD Note: ${opd.note}
About: ${h.note || ''}`;
  }).join('\n\n---\n\n');
}

async function sendMsg() {
  const input = document.getElementById('chatIn');
  const text = input.value.trim();
  if (!text) return;

  soundClick();
  appendMsg('user', text);
  input.value = '';
  chatHistory.push({ role: 'user', content: text });

  const typingId = 'typing-' + Date.now();
  appendMsg('bot', '<span></span><span></span><span></span>', typingId);
  document.getElementById(typingId).classList.add('typing');

  // Determine intent
  const hospitalQuery       = isHospitalQuery(text);
  const diseaseQuery        = isDiseaseQuery(text);
  const specialistDetected  = isCategorySpecialistQuery(text);   // NEW

  // Find relevant records from local databases
  const treatmentMatches = findLocalMatches(text);
  // If a specialist query was detected, also filter hospitals by that specialty
  let hospitalMatches = findHospitalMatches(text);
  if (specialistDetected && hospitalMatches.length === 0) {
    // Broaden: any hospital that covers the detected specialty
    hospitalMatches = HOSPITALS
      .filter(h => h.specialties.includes(specialistDetected.entry.spec))
      .slice(0, 3);
  }

  // Build context sections
  const treatmentContext = treatmentMatches.length > 0
    ? treatmentMatches.map(t => {
        const cat = CATS[t.cat];
        return `Treatment: ${t.title} (${cat.label}, severity: ${t.sev})
Warning: ${t.warn}
Steps: ${t.steps.map((s,i) => `${i+1}. ${s}`).join(' | ')}
Do NOT: ${(t.donot||[]).join(' | ')}
When to seek help: ${t.seek||''}
ID: ${t.id}`;
      }).join('\n\n---\n\n')
    : 'No specific first-aid treatment found in local database.';

  const hospitalContext = hospitalMatches.length > 0
    ? buildHospitalContext(hospitalMatches)
    : 'No specific hospital match found in local database.';

  // Detect query intent flags
  const isEmergencyUrgent = /\b(help|emergency|urgent|now|dying|collapsed|unconscious|not breathing|call|sos|bleeding badly|severe)\b/i.test(text);

  // Specialist context string for prompt
  const specialistContext = specialistDetected
    ? `\nSPECIALIST CONTEXT: The user's query maps to the "${CATS[specialistDetected.catKey]?.label}" category. The appropriate specialist is a "${specialistDetected.entry.specialist}". Hospitals below have been pre-filtered to include this specialty where possible.`
    : '';

  const systemPrompt = `You are HealthGuard AI — the intelligent assistant inside HealthGuard Pro, a first-aid and medical reference app used in Kolkata, India.

════════ YOUR PRIMARY ROLE ════════
You answer three types of questions:
1. 🩺 FIRST AID / EMERGENCIES — Immediate step-by-step guidance (life-saving priority)
2. 🦠 DISEASE INFORMATION — Symptoms, causes, prevention, general treatment
3. 🏥 HOSPITAL FINDER — Kolkata hospitals by specialty, proximity, or emergency capability

════════ LOCAL DATABASE CONTEXT ════════
The following data was retrieved from the app's own database specifically for this user query. USE THIS DATA as your primary source — do not invent steps or hospitals that are not listed here.
${specialistContext}

MATCHED FIRST-AID PROTOCOLS (top results, ranked by relevance):
${treatmentMatches.length > 0 ? treatmentContext : '— No exact protocol match. Use your medical knowledge and be clear you are providing general guidance.'}

MATCHED HOSPITALS (Kolkata) — including OPD hours:
${hospitalMatches.length > 0 ? hospitalContext : '— No specific hospital match. Suggest the user call 108 (ambulance) or 112 (national emergency) and visit the nearest government hospital.'}

════════ RESPONSE RULES ════════
ACCURACY:
- If a matched protocol exists above, base your answer on it. Do NOT contradict the protocol steps.
- If no protocol matches, provide correct general first-aid from medical knowledge and clearly state it is general guidance.
- Never invent hospital names, phone numbers, addresses, or OPD timings.
- Never diagnose a condition — provide information only.

OPD HOURS:
- When recommending a hospital, always mention its OPD hours (Weekdays / Saturday / Sunday) and the OPD note from the context above.
- Remind users to call ahead to confirm timings as they may change on public holidays.

SPECIALIST GUIDANCE:
- When the user asks about which doctor or specialist to see, name the specialist type explicitly (e.g., "You should see a Cardiologist" or "Visit an Orthopaedic Surgeon").
- If a specialist query was detected, open your response by naming the specialist, then recommend the matched hospitals with their OPD hours.

FORMAT:
- Use HTML: <strong> for emphasis, <br> for line breaks, ordered lists (<ol><li>) for steps.
- Lead with the most critical action (call 112/108 for life-threatening cases).
- For first aid: use numbered steps mirroring the protocol.
- For disease info: cover symptoms → causes → prevention → when to see a doctor.
- For hospitals: list name, phone, emergency availability, specialties, and OPD hours.
- Keep responses under 350 words unless the topic demands more detail.

TONE:
- Calm, clear, and directive — especially in emergencies.
- Always close with: recommend professional medical consultation for serious concerns.
- If the question is unrelated to health/medicine, politely redirect.
${isEmergencyUrgent ? '\n⚡ PRIORITY: This appears to be an active emergency. Lead immediately with "CALL 108 or 112 NOW" before anything else.' : ''}`;

  try {
    const response = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        model: 'claude-sonnet-4-20250514',
        max_tokens: 1000,
        system: systemPrompt,
        messages: chatHistory.slice(-10)
      })
    });

    const data = await response.json();
    const replyText = data?.content?.[0]?.text || '';

    // Remove typing indicator
    const typingEl = document.getElementById(typingId);
    if (typingEl) typingEl.remove();

    if (replyText) {
      appendMsg('bot', replyText);
      chatHistory.push({ role: 'assistant', content: replyText });

      // Show clickable treatment protocol cards if matched
      if (treatmentMatches.length > 0 && !hospitalQuery) {
        const cardsHtml = treatmentMatches.map(t => {
          const cat = CATS[t.cat];
          return `<div onclick="openTreatment('${t.id}')" style="display:flex;align-items:center;gap:.6rem;padding:.5rem .7rem;margin-top:.4rem;background:var(--bg3);border:1px solid var(--glassborder);border-radius:10px;cursor:pointer;transition:border-color .2s" onmouseover="this.style.borderColor='var(--cyan)'" onmouseout="this.style.borderColor='var(--glassborder)'">
            <i class="fas ${t.icon}" style="color:${cat.color};width:14px;flex-shrink:0"></i>
            <span style="font-size:.8rem;font-weight:600;flex:1">${t.title}</span>
            <span class="sev-badge sev-${t.sev}">${t.sev}</span>
            <i class="fas fa-chevron-right" style="color:var(--text3);font-size:.65rem"></i>
          </div>`;
        }).join('');
        const wrapper = document.createElement('div');
        wrapper.className = 'msg bot';
        wrapper.style.cssText = 'background:transparent;border:none;padding:.2rem 0;max-width:100%';
        wrapper.innerHTML = `<div style="font-size:.72rem;color:var(--text3);margin-bottom:.3rem"><i class="fas fa-book-medical" style="margin-right:.3rem"></i>Relevant protocols:</div>${cardsHtml}`;
        document.getElementById('chatBody').appendChild(wrapper);
        document.getElementById('chatBody').scrollTop = document.getElementById('chatBody').scrollHeight;
      }

      // Show rich hospital cards (with OPD hours + specialist badge) if matched
      if (hospitalMatches.length > 0 && (hospitalQuery || specialistDetected || treatmentMatches.length === 0)) {
        const mapsQ = h => encodeURIComponent(h.name + ', Kolkata');
        const hospCardsHtml = hospitalMatches.map(h => {
          const isGovt = h.type === 'govt';
          const opd    = getOpdHours(h.name);
          // Determine which specialist badge to show
          const specBadge = specialistDetected
            ? `<span style="font-size:.62rem;background:rgba(99,102,241,.15);color:#818cf8;border:1px solid rgba(99,102,241,.3);border-radius:6px;padding:.1rem .4rem;margin-left:.3rem"><i class="fas fa-user-doctor" style="margin-right:.2rem"></i>${specialistDetected.entry.specialist}</span>`
            : '';
          // Specialty tags
          const specTags = h.specialties.slice(0,4).map(s => {
            const cfg = SPEC_CONFIG[s];
            return cfg
              ? `<span style="font-size:.6rem;padding:.1rem .35rem;border-radius:5px;background:${cfg.color}18;color:${cfg.color};border:1px solid ${cfg.color}33"><i class="fas ${cfg.icon}" style="margin-right:.18rem"></i>${cfg.label}</span>`
              : '';
          }).join('');
          return `<div style="padding:.65rem .8rem;margin-top:.4rem;background:var(--bg3);border:1px solid var(--glassborder);border-radius:12px;transition:border-color .2s" onmouseover="this.style.borderColor='var(--cyan)'" onmouseout="this.style.borderColor='var(--glassborder)'">
            <div style="display:flex;align-items:flex-start;gap:.5rem;margin-bottom:.3rem">
              <i class="fas ${isGovt ? 'fa-landmark' : 'fa-building-user'}" style="color:${isGovt ? '#22c55e' : '#3b82f6'};width:14px;flex-shrink:0;margin-top:.15rem"></i>
              <div style="flex:1;min-width:0">
                <span style="font-size:.83rem;font-weight:700">${h.name}</span>
                ${h.emergency ? '<span style="font-size:.62rem;background:rgba(239,68,68,.15);color:#ef4444;border:1px solid rgba(239,68,68,.3);border-radius:6px;padding:.1rem .4rem;margin-left:.3rem">24×7 ER</span>' : ''}
                ${specBadge}
              </div>
            </div>
            ${specTags ? `<div style="display:flex;flex-wrap:wrap;gap:.25rem;margin-bottom:.35rem">${specTags}</div>` : ''}
            <div style="font-size:.71rem;color:var(--text3);margin-bottom:.3rem"><i class="fas fa-location-dot" style="margin-right:.3rem"></i>${h.address}</div>
            <div style="background:rgba(0,230,118,.06);border:1px solid rgba(0,230,118,.18);border-radius:8px;padding:.35rem .55rem;margin-bottom:.35rem">
              <div style="font-size:.68rem;font-weight:600;color:var(--cyan);margin-bottom:.18rem"><i class="fas fa-clock" style="margin-right:.3rem"></i>OPD Hours</div>
              <div style="font-size:.67rem;color:var(--text2);line-height:1.55">
                <span style="display:inline-block;min-width:5.5rem;color:var(--text3)">Mon–Fri:</span>${opd.weekday}<br>
                <span style="display:inline-block;min-width:5.5rem;color:var(--text3)">Saturday:</span>${opd.saturday}<br>
                <span style="display:inline-block;min-width:5.5rem;color:var(--text3)">Sunday:</span>${opd.sunday}
              </div>
              ${opd.note ? `<div style="font-size:.63rem;color:var(--text3);margin-top:.22rem;font-style:italic"><i class="fas fa-circle-info" style="margin-right:.2rem"></i>${opd.note}</div>` : ''}
            </div>
            <div style="display:flex;gap:.5rem;flex-wrap:wrap">
              <a href="tel:${h.phone.replace(/[^0-9+]/g,'')}" style="display:inline-flex;align-items:center;gap:.3rem;font-size:.72rem;padding:.28rem .65rem;background:rgba(34,197,94,.12);color:#22c55e;border:1px solid rgba(34,197,94,.3);border-radius:7px;text-decoration:none"><i class="fas fa-phone"></i>${h.phone}</a>
              <a href="https://www.google.com/maps/search/?api=1&query=${mapsQ(h)}" target="_blank" rel="noopener" style="display:inline-flex;align-items:center;gap:.3rem;font-size:.72rem;padding:.28rem .65rem;background:rgba(59,130,246,.12);color:#3b82f6;border:1px solid rgba(59,130,246,.3);border-radius:7px;text-decoration:none"><i class="fas fa-map-location-dot"></i>Directions</a>
            </div>
          </div>`;
        }).join('');
        const hospWrapper = document.createElement('div');
        hospWrapper.className = 'msg bot';
        hospWrapper.style.cssText = 'background:transparent;border:none;padding:.2rem 0;max-width:100%';
        const headerIcon  = specialistDetected ? 'fa-user-doctor' : 'fa-hospital';
        const headerLabel = specialistDetected
          ? `Recommended hospitals — <em>${specialistDetected.entry.specialist}</em>:`
          : 'Matched hospitals:';
        hospWrapper.innerHTML = `<div style="font-size:.72rem;color:var(--text3);margin-bottom:.3rem"><i class="fas ${headerIcon}" style="margin-right:.3rem"></i>${headerLabel}</div>${hospCardsHtml}`;
        document.getElementById('chatBody').appendChild(hospWrapper);
        document.getElementById('chatBody').scrollTop = document.getElementById('chatBody').scrollHeight;
      }

    } else {
      throw new Error('Empty response');
    }

  } catch (err) {
    // Graceful fallback if API fails
    const typingEl = document.getElementById(typingId);
    if (typingEl) typingEl.remove();

    if (hospitalQuery && hospitalMatches.length > 0) {
      const h = hospitalMatches[0];
      const opd = getOpdHours(h.name);
      const fallback = `<strong><i class="fas fa-hospital" style="color:var(--cyan)"></i> ${h.name}</strong><br>
<i class="fas fa-location-dot" style="color:var(--text3)"></i> ${h.address}<br>
<i class="fas fa-phone" style="color:var(--text3)"></i> ${h.phone}<br>
${h.emergency ? '✅ 24×7 Emergency available' : '⚠️ No 24×7 emergency'}<br>
<strong>OPD:</strong> Mon–Fri ${opd.weekday} | Sat ${opd.saturday} | Sun ${opd.sunday}<br>
<em>Use the Hospital Finder button above for more options.</em>`;
      appendMsg('bot', fallback);
    } else if (specialistDetected && hospitalMatches.length > 0) {
      const h = hospitalMatches[0];
      const opd = getOpdHours(h.name);
      const fallback = `You should consult a <strong>${specialistDetected.entry.specialist}</strong>.<br><br>
<strong>${h.name}</strong><br>
<i class="fas fa-phone"></i> ${h.phone}<br>
OPD Mon–Fri: ${opd.weekday}<br>
${opd.note ? `<em>${opd.note}</em><br>` : ''}
<em>Use the Hospital Finder for more options.</em>`;
      appendMsg('bot', fallback);
    } else if (treatmentMatches.length > 0) {
      const m = treatmentMatches[0];
      const cat = CATS[m.cat];
      const fallback = `<strong><i class="fas ${m.icon}" style="color:${cat.color}"></i> ${m.title}</strong><br><br>
${m.warn}<br><br>
<strong>Key steps:</strong><br>
${m.steps.slice(0,4).map((s,i)=>`${i+1}. ${s}`).join('<br>')}<br><br>
<em>👉 <a href="#" onclick="openTreatment('${m.id}');return false;" style="color:var(--cyan)">View full protocol</a></em>`;
      appendMsg('bot', fallback);
    } else {
      appendMsg('bot', "I couldn't find guidance for that. You can ask me about:<br>🩺 First aid — e.g. <em>burn</em>, <em>CPR</em>, <em>choking</em><br>🦠 Diseases — e.g. <em>symptoms of dengue</em>, <em>what is diabetes</em><br>🏥 Hospitals — e.g. <em>cardiac hospital in Kolkata</em><br>👨‍⚕️ Specialists — e.g. <em>which doctor for heart pain</em>");
    }
  }
}

function quickMsg(text) {
  document.getElementById('chatIn').value = text;
  sendMsg();
}

// ==========================================
// UTILITIES
// ==========================================
function showHospitals() {
  soundOpen();

  // ── Inject modal + styles once ──
  if (!document.getElementById('hospModal')) {
    // Styles
    const style = document.createElement('style');
    style.id = 'hospModalStyle';
    style.textContent = `
      #hospModal {
        display: none;
        position: fixed;
        inset: 0;
        z-index: 9999;
        background: rgba(0,0,0,0.72);
        backdrop-filter: blur(6px);
        align-items: center;
        justify-content: center;
        padding: 1rem;
        animation: hm-fade-in 0.22s ease;
      }
      #hospModal.open { display: flex; }
      @keyframes hm-fade-in { from { opacity:0 } to { opacity:1 } }

      #hospModalBox {
        background: var(--bg2, #0d1117);
        border: 1px solid var(--glassborder, rgba(255,255,255,0.1));
        border-radius: 20px;
        width: 100%;
        max-width: 860px;
        max-height: 90vh;
        display: flex;
        flex-direction: column;
        overflow: hidden;
        box-shadow: 0 32px 80px rgba(0,0,0,0.6);
        animation: hm-slide-up 0.25s cubic-bezier(.22,.68,0,1.2);
      }
      @keyframes hm-slide-up { from { transform:translateY(40px); opacity:0 } to { transform:translateY(0); opacity:1 } }

      #hospModalHead {
        padding: 1.2rem 1.4rem 0.8rem;
        border-bottom: 1px solid var(--glassborder, rgba(255,255,255,0.08));
        flex-shrink: 0;
      }
      #hospModalHead h2 {
        margin: 0 0 0.8rem;
        font-size: 1.1rem;
        display: flex;
        align-items: center;
        gap: 0.5rem;
      }
      .hm-tabs {
        display: flex;
        gap: 0.4rem;
        flex-wrap: wrap;
        margin-bottom: 0.7rem;
      }
      .hm-tab {
        padding: 0.3rem 0.9rem;
        border-radius: 99px;
        border: 1px solid var(--glassborder, rgba(255,255,255,0.15));
        background: transparent;
        color: var(--text2, #aaa);
        font-size: 0.78rem;
        cursor: pointer;
        transition: all 0.18s;
        font-weight: 500;
      }
      .hm-tab.active, .hm-tab:hover {
        background: var(--cyan, #00e676);
        color: var(--btn-primary-color, #000);
        border-color: var(--cyan, #00e676);
      }
      .hm-spec-filters {
        display: flex;
        gap: 0.35rem;
        flex-wrap: wrap;
      }
      .hm-spec {
        padding: 0.2rem 0.7rem;
        border-radius: 99px;
        border: 1px solid var(--glassborder, rgba(255,255,255,0.1));
        background: transparent;
        font-size: 0.7rem;
        cursor: pointer;
        transition: all 0.15s;
        color: var(--text3, #666);
      }
      .hm-spec.active {
        color: var(--btn-primary-color, #000);
        border-color: transparent;
      }
      .hm-search {
        width: 100%;
        padding: 0.55rem 0.9rem;
        background: var(--bg3, #161b22);
        border: 1px solid var(--glassborder, rgba(255,255,255,0.1));
        border-radius: 10px;
        color: var(--text1, #eee);
        font-size: 0.85rem;
        margin-top: 0.7rem;
        outline: none;
        transition: border-color 0.2s;
      }
      .hm-search:focus { border-color: var(--cyan, #00e676); }

      #hospModalBody {
        overflow-y: auto;
        padding: 1rem 1.2rem 1.4rem;
        flex: 1;
        scrollbar-width: thin;
        scrollbar-color: var(--cyan) transparent;
      }
      #hospModalBody::-webkit-scrollbar { width: 4px; }
      #hospModalBody::-webkit-scrollbar-thumb { background: var(--cyan); border-radius: 99px; }

      .hm-grid {
        display: grid;
        grid-template-columns: repeat(auto-fill, minmax(340px, 1fr));
        gap: 0.85rem;
      }
      .hm-card {
        background: var(--glass, rgba(255,255,255,0.04));
        border: 1px solid var(--glassborder, rgba(255,255,255,0.08));
        border-radius: 14px;
        padding: 1rem;
        display: flex;
        flex-direction: column;
        gap: 0.5rem;
        transition: border-color 0.2s, transform 0.15s;
        position: relative;
        overflow: hidden;
      }
      .hm-card:hover {
        border-color: var(--cyan, #00e676);
        transform: translateY(-2px);
      }
      .hm-card-top {
        display: flex;
        align-items: flex-start;
        gap: 0.6rem;
      }
      .hm-type-icon {
        width: 38px;
        height: 38px;
        border-radius: 10px;
        display: flex;
        align-items: center;
        justify-content: center;
        font-size: 1rem;
        flex-shrink: 0;
      }
      .hm-type-icon.govt { background: rgba(34,197,94,0.15); color: #22c55e; }
      .hm-type-icon.pvt  { background: rgba(0,230,118,0.12); color: #00e676; }
      .hm-card-title { font-size: 0.9rem; font-weight: 700; line-height: 1.3; }
      .hm-card-addr  { font-size: 0.72rem; color: var(--text3, #666); display:flex; align-items:flex-start; gap:0.3rem; }
      .hm-badge-row  { display: flex; gap: 0.3rem; flex-wrap: wrap; margin-top: 0.2rem; }
      .hm-badge {
        font-size: 0.62rem;
        padding: 0.15rem 0.5rem;
        border-radius: 99px;
        font-weight: 600;
        text-transform: capitalize;
        letter-spacing: 0.02em;
      }
      .hm-type-badge.govt { background: rgba(34,197,94,0.15); color: #22c55e; border: 1px solid #22c55e44; }
      .hm-type-badge.pvt  { background: rgba(0,230,118,0.1);  color: #00e676; border: 1px solid #00e67644; }
      .hm-emr-badge { background: rgba(239,68,68,0.15); color: #ef4444; border: 1px solid #ef444444; }
      .hm-note { font-size: 0.72rem; color: var(--text3, #666); font-style: italic; line-height: 1.4; }
      .hm-actions { display: flex; gap: 0.5rem; margin-top: 0.3rem; }
      .hm-btn {
        flex: 1;
        padding: 0.4rem 0;
        border-radius: 8px;
        font-size: 0.75rem;
        font-weight: 600;
        cursor: pointer;
        border: none;
        display: flex;
        align-items: center;
        justify-content: center;
        gap: 0.35rem;
        transition: filter 0.15s, transform 0.1s;
        text-decoration: none;
      }
      .hm-btn:active { transform: scale(0.96); }
      .hm-btn.call { background: rgba(96,165,250,0.18); color: #93c5fd; border: 1px solid rgba(96,165,250,0.4); }
      .hm-btn.call:hover { filter: brightness(1.25); }
      .hm-btn.dir  { background: rgba(180,120,80,0.18); color: #c8956a; border: 1px solid rgba(180,120,80,0.4); }
      .hm-btn.dir:hover { filter: brightness(1.25); }
      .hm-close-btn {
        position: absolute;
        top: 1rem;
        right: 1.1rem;
        background: var(--bg3, #161b22);
        border: 1px solid var(--glassborder, rgba(255,255,255,0.1));
        color: var(--text2, #aaa);
        width: 32px;
        height: 32px;
        border-radius: 50%;
        cursor: pointer;
        font-size: 0.9rem;
        display: flex;
        align-items: center;
        justify-content: center;
        transition: background 0.15s;
        flex-shrink: 0;
      }
      .hm-close-btn:hover { background: rgba(239,68,68,0.2); color: #ef4444; }
      .hm-count { font-size: 0.72rem; color: var(--text3); margin-bottom: 0.6rem; }
      .hm-empty { text-align:center; color:var(--text3); padding:3rem 1rem; }

      /* ─── Light Mode overrides ─── */
      .light #hospModal { background: rgba(15,23,42,.55); }
      .light #hospModalBox { background: #ffffff; border-color: rgba(0,0,0,.10); box-shadow: 0 12px 50px rgba(0,0,0,.15); }
      .light #hospModalHead { border-color: rgba(0,0,0,.08); }
      .light .hm-tab { color: #475569; border-color: rgba(0,0,0,.12); }
      .light .hm-tab.active, .light .hm-tab:hover { background: var(--cyan); color: #fff; border-color: var(--cyan); }
      .light .hm-spec { color: #64748b; border-color: rgba(0,0,0,.10); }
      .light .hm-spec.active { color: #fff; }
      .light .hm-search { background: #f8fafc; border-color: rgba(0,0,0,.10); color: #0f172a; }
      .light .hm-card { background: #f8fafc; border-color: rgba(0,0,0,.08); }
      .light .hm-card:hover { border-color: var(--cyan); }
      .light .hm-card-title { color: #0f172a; }
      .light .hm-type-icon.govt { background: rgba(0,168,84,.12); color: #065f46; }
      .light .hm-type-icon.pvt  { background: rgba(0,168,84,.08); color: #00a854; }
      .light .hm-type-badge.govt { background: rgba(0,168,84,.10); color: #065f46; border-color: rgba(0,168,84,.25); }
      .light .hm-type-badge.pvt  { background: rgba(0,168,84,.07); color: #00a854; border-color: rgba(0,168,84,.20); }
      .light .hm-emr-badge { background: rgba(224,0,43,.10); color: #b91c1c; border-color: rgba(224,0,43,.25); }
      .light .hm-btn.call { background: rgba(59,130,246,.10); color: #1d4ed8; border-color: rgba(59,130,246,.25); }
      .light .hm-btn.dir  { background: rgba(120,80,40,.08); color: #92400e; border-color: rgba(120,80,40,.20); }
      .light .hm-close-btn { background: #f1f5f9; border-color: rgba(0,0,0,.10); color: #475569; }
      .light .hm-close-btn:hover { background: rgba(224,0,43,.08); color: #b91c1c; }
    `;
    document.head.appendChild(style);

    // Modal HTML
    const modal = document.createElement('div');
    modal.id = 'hospModal';
    modal.innerHTML = `
      <div id="hospModalBox">
        <div id="hospModalHead">
          <div style="display:flex;align-items:center;justify-content:space-between">
            <h2><i class="fas fa-hospital" style="color:var(--cyan)"></i> Kolkata Hospitals</h2>
            <button class="hm-close-btn" onclick="closeHospModal()"><i class="fas fa-times"></i></button>
          </div>
          <div class="hm-tabs" id="hmTabs">
            <button class="hm-tab active" data-type="all" onclick="hmSetType('all',this)">All <span id="hmCountAll"></span></button>
            <button class="hm-tab" data-type="govt" onclick="hmSetType('govt',this)"><i class="fas fa-landmark" style="margin-right:.3rem"></i>Government <span id="hmCountGovt"></span></button>
            <button class="hm-tab" data-type="pvt" onclick="hmSetType('pvt',this)"><i class="fas fa-building" style="margin-right:.3rem"></i>Private <span id="hmCountPvt"></span></button>
          </div>
          <div class="hm-spec-filters" id="hmSpecFilters"></div>
          <input class="hm-search" id="hmSearch" type="text" placeholder="🔍  Search hospital name or address…" oninput="hmRender()">
        </div>
        <div id="hospModalBody">
          <div class="hm-count" id="hmResultCount"></div>
          <div class="hm-grid" id="hmGrid"></div>
        </div>
      </div>
    `;
    document.body.appendChild(modal);
    modal.addEventListener('click', e => { if (e.target === modal) closeHospModal(); });
  }

  // Open with spring animation
  const hospModal = document.getElementById('hospModal');
  const hospBox   = document.getElementById('hospModalBox');
  hospModal.classList.add('open');
  document.body.style.overflow = 'hidden';
  if (hospBox) {
    hospBox.style.transition = 'none';
    hospBox.style.transform = 'translateY(52px) scale(0.93)';
    hospBox.style.opacity = '0';
    requestAnimationFrame(() => {
      requestAnimationFrame(() => {
        hospBox.style.transition = 'transform .44s cubic-bezier(.22,.68,0,1.2), opacity .32s cubic-bezier(.22,.68,0,1.2)';
        hospBox.style.transform = 'translateY(0) scale(1)';
        hospBox.style.opacity = '1';
      });
    });
  }
  hmSetType('all', document.querySelector('.hm-tab[data-type="all"]'));
  hmBuildSpecFilters();
  hmRender();
}

function closeHospModal() {
  soundClose();
  const modal = document.getElementById('hospModal');
  if (!modal) return;
  const box = document.getElementById('hospModalBox');
  if (box) {
    box.style.transition = 'transform .28s cubic-bezier(.4,0,.6,1), opacity .25s ease';
    box.style.transform = 'translateY(36px) scale(0.95)';
    box.style.opacity = '0';
  }
  modal.style.transition = 'opacity .28s ease';
  modal.style.opacity = '0';
  setTimeout(() => {
    modal.classList.remove('open');
    modal.style.opacity = '';
    modal.style.transition = '';
    if (box) { box.style.transform = ''; box.style.opacity = ''; box.style.transition = ''; }
    document.body.style.overflow = '';
  }, 290);
}

// Specialty display config
const SPEC_CONFIG = {
  cardiac:     { label:'Cardiac',       color:'#ff2d55', icon:'fa-heart-pulse' },
  neuro:       { label:'Neuro',         color:'#a855f7', icon:'fa-brain' },
  trauma:      { label:'Trauma',        color:'#ffb300', icon:'fa-person-falling' },
  burns:       { label:'Burns',         color:'#ff7043', icon:'fa-fire-flame-curved' },
  obstetric:   { label:'Obstetric',     color:'#db2777', icon:'fa-person-pregnant' },
  pediatric:   { label:'Pediatric',     color:'#ec4899', icon:'fa-baby' },
  orthopedic:  { label:'Orthopaedic',   color:'#3b82f6', icon:'fa-bone' },
  cancer:      { label:'Oncology',      color:'#8b5cf6', icon:'fa-ribbon' },
  transplant:  { label:'Transplant',    color:'#06b6d4', icon:'fa-hand-holding-medical' },
  infectious:  { label:'Infectious',    color:'#ef4444', icon:'fa-virus' },
  mental:      { label:'Psychiatry',    color:'#6366f1', icon:'fa-brain' },
  diabetic:    { label:'Diabetes',      color:'#0ea5e9', icon:'fa-droplet' },
  eye:         { label:'Eye & ENT',     color:'#06b6d4', icon:'fa-eye' },
  general:     { label:'General',       color:'#64748b', icon:'fa-stethoscope' },
};

let _hmType = 'all';
let _hmSpec = 'all';

function hmSetType(type, btn) {
  _hmType = type;
  _hmSpec = 'all';
  document.querySelectorAll('.hm-tab').forEach(b => b.classList.remove('active'));
  if (btn) btn.classList.add('active');
  document.querySelectorAll('.hm-spec').forEach(b => { b.classList.toggle('active', b.dataset.spec === 'all'); });
  hmRender();
}

function hmSetSpec(spec, btn) {
  _hmSpec = spec;
  document.querySelectorAll('.hm-spec').forEach(b => b.classList.remove('active'));
  if (btn) btn.classList.add('active');
  hmRender();
}

function hmBuildSpecFilters() {
  const container = document.getElementById('hmSpecFilters');
  if (!container || container.childElementCount > 0) return;

  // Collect all unique specialties
  const all = new Set();
  HOSPITALS.forEach(h => h.specialties.forEach(s => all.add(s)));

  const allBtn = document.createElement('button');
  allBtn.className = 'hm-spec active';
  allBtn.dataset.spec = 'all';
  allBtn.textContent = 'All Specialties';
  allBtn.style.cssText = `background:rgba(0,230,118,0.12);color:var(--cyan);border-color:var(--cyan)`;
  allBtn.onclick = () => hmSetSpec('all', allBtn);
  container.appendChild(allBtn);

  [...all].sort().forEach(spec => {
    const cfg = SPEC_CONFIG[spec];
    if (!cfg) return;
    const btn = document.createElement('button');
    btn.className = 'hm-spec';
    btn.dataset.spec = spec;
    btn.innerHTML = `<i class="fas ${cfg.icon}" style="margin-right:.25rem"></i>${cfg.label}`;
    btn.style.setProperty('--sc', cfg.color);
    btn.addEventListener('click', () => hmSetSpec(spec, btn));
    btn.addEventListener('mouseenter', () => { if (!btn.classList.contains('active')) btn.style.cssText = `color:${cfg.color};border-color:${cfg.color}44;background:${cfg.color}18`; });
    btn.addEventListener('mouseleave', () => { if (!btn.classList.contains('active')) btn.style.cssText = ''; });
    // active style
    const origOnClick = btn.onclick;
    btn.onclick = () => {
      hmSetSpec(spec, btn);
      btn.style.cssText = `background:${cfg.color}22;color:${cfg.color};border-color:${cfg.color}`;
    };
    container.appendChild(btn);
  });

  // Update tab counts
  const govtC = HOSPITALS.filter(h => h.type === 'govt').length;
  const pvtC  = HOSPITALS.filter(h => h.type === 'pvt').length;
  document.getElementById('hmCountAll').textContent  = `(${HOSPITALS.length})`;
  document.getElementById('hmCountGovt').textContent = `(${govtC})`;
  document.getElementById('hmCountPvt').textContent  = `(${pvtC})`;
}

function hmRender() {
  const grid    = document.getElementById('hmGrid');
  const countEl = document.getElementById('hmResultCount');
  const query   = (document.getElementById('hmSearch')?.value || '').toLowerCase().trim();
  if (!grid) return;

  let list = HOSPITALS;
  if (_hmType !== 'all') list = list.filter(h => h.type === _hmType);
  if (_hmSpec !== 'all') list = list.filter(h => h.specialties.includes(_hmSpec));
  if (query) list = list.filter(h =>
    h.name.toLowerCase().includes(query) ||
    h.address.toLowerCase().includes(query) ||
    h.specialties.some(s => (SPEC_CONFIG[s]?.label || s).toLowerCase().includes(query))
  );

  countEl.textContent = `${list.length} hospital${list.length !== 1 ? 's' : ''} found`;

  if (list.length === 0) {
    grid.innerHTML = `<div class="hm-empty" style="grid-column:1/-1"><i class="fas fa-hospital-slash" style="font-size:2rem;margin-bottom:.7rem;display:block;color:var(--text3)"></i>No hospitals match your filters.</div>`;
    return;
  }

  grid.innerHTML = list.map(h => {
    const isGovt = h.type === 'govt';
    const mapsQ  = encodeURIComponent(h.name + ', Kolkata');
    const specBadges = h.specialties.map(s => {
      const cfg = SPEC_CONFIG[s];
      if (!cfg) return '';
      return `<span class="hm-badge" style="background:${cfg.color}18;color:${cfg.color};border:1px solid ${cfg.color}33">
                <i class="fas ${cfg.icon}" style="margin-right:.25rem;font-size:.58rem"></i>${cfg.label}
              </span>`;
    }).join('');

    return `
      <div class="hm-card">
        <div class="hm-card-top">
          <div class="hm-type-icon ${h.type}">
            <i class="fas ${isGovt ? 'fa-landmark' : 'fa-building-user'}"></i>
          </div>
          <div style="flex:1;min-width:0">
            <div class="hm-card-title">${h.name}</div>
            <div style="display:flex;gap:.4rem;margin-top:.3rem;flex-wrap:wrap">
              <span class="hm-badge hm-type-badge ${h.type}">${isGovt ? 'Government' : 'Private'}</span>
              ${h.emergency ? '<span class="hm-badge hm-emr-badge"><i class="fas fa-truck-medical" style="margin-right:.25rem"></i>24×7 Emergency</span>' : ''}
              ${h.beds ? `<span class="hm-badge" style="background:rgba(255,255,255,0.06);color:var(--text2);border:1px solid var(--glassborder)"><i class="fas fa-bed" style="margin-right:.25rem"></i>${h.beds} beds</span>` : ''}
            </div>
          </div>
        </div>
        <div class="hm-card-addr"><i class="fas fa-location-dot" style="color:var(--text3);margin-top:.1rem;flex-shrink:0"></i><span>${h.address}</span></div>
        <div class="hm-badge-row">${specBadges}</div>
        ${h.note ? `<div class="hm-note"><i class="fas fa-circle-info" style="margin-right:.3rem;color:var(--cyan)"></i>${h.note}</div>` : ''}
        <div class="hm-actions">
          <a class="hm-btn call" href="tel:${h.phone.replace(/[^0-9+]/g,'')}">
            <i class="fas fa-phone"></i>${h.phone}
          </a>
          <a class="hm-btn dir" href="https://www.google.com/maps/search/?api=1&query=${mapsQ}" target="_blank" rel="noopener">
            <i class="fas fa-map-location-dot"></i>Directions
          </a>
        </div>
      </div>
    `;
  }).join('');
}

function scrollToEl(sel) {
  soundClick();
  setTimeout(() => document.querySelector(sel)?.scrollIntoView({behavior:'smooth'}), 100);
}

// ==========================================
// INJECT LOCAL HOSPITALS HERO BUTTON
// ==========================================
function injectHospitalButton() {
  // Already injected?
  if (document.getElementById('heroHospBtn')) return;

  // Find the parent container that holds the Browse Treatments / Ask AI buttons.
  // Strategy: locate any <button> or <a> whose onclick/text references
  // scrollToEl('#treatments') or toggleChat, then grab its parent container.
  let container = null;

  // 1) Try common wrapper class/id names used in medical/emergency apps
  const selectors = [
    '.hero-actions', '.hero-btns', '.hero-cta', '.cta-buttons',
    '.quick-actions', '.action-btns', '#heroActions', '#heroBtns',
    '.hero-buttons', '.hero-links', '.hero-row'
  ];
  for (const sel of selectors) {
    const el = document.querySelector(sel);
    if (el) { container = el; break; }
  }

  // 2) Fallback: find button whose text mentions "Browse" or "Treatment"
  if (!container) {
    const allBtns = [...document.querySelectorAll('button, a[href="#treatments"], a[href="#"]')];
    const browseBtn = allBtns.find(b =>
      /browse|treatment|treat/i.test(b.textContent) ||
      (b.getAttribute('onclick') || '').includes('treatments')
    );
    if (browseBtn) container = browseBtn.parentElement;
  }

  // 3) Fallback: find button that calls toggleChat / openChat / Ask AI
  if (!container) {
    const allBtns = [...document.querySelectorAll('button, a')];
    const aiBtn = allBtns.find(b =>
      /ask ai|ai assistant|chat/i.test(b.textContent) ||
      /toggleChat|openChat/i.test(b.getAttribute('onclick') || '')
    );
    if (aiBtn) container = aiBtn.parentElement;
  }

  if (!container) return; // HTML not yet in DOM — will retry below

  // Build the button, matching the style of its siblings automatically
  const btn = document.createElement('button');
  btn.id = 'heroHospBtn';
  btn.setAttribute('onclick', 'showHospitals()');

  // Mirror inline style from first sibling button so it blends in visually
  const sibling = container.querySelector('button, a');
  if (sibling) {
    btn.className = sibling.className;
    // Copy any inline styles that define shape/color, then override accent
    const sibStyle = sibling.getAttribute('style') || '';
    btn.setAttribute('style', sibStyle);
  }

  // Ensure a readable, consistent look regardless of sibling style
  btn.style.cssText += `
    display:inline-flex; align-items:center; gap:.45rem;
    cursor:pointer; font-weight:600; letter-spacing:.02em;
  `;

  btn.innerHTML = '<i class="fas fa-hospital-user"></i> Hospital';

  // Inject as the last child of the container (after Browse + Ask AI)
  container.appendChild(btn);

  // Also inject a one-time CSS rule to keep the button styled even if no sibling class matches
  if (!document.getElementById('heroHospBtnStyle')) {
    const s = document.createElement('style');
    s.id = 'heroHospBtnStyle';
    s.textContent = `
      #heroHospBtn {
        background: rgba(34,197,94,.12);
        border: 1px solid rgba(34,197,94,.4);
        color: #22c55e;
        border-radius: 99px;
        padding: .55rem 1.3rem;
        font-size: .9rem;
        transition: background .2s, transform .15s, box-shadow .2s;
      }
      #heroHospBtn:hover {
        background: rgba(34,197,94,.22);
        box-shadow: 0 0 14px rgba(34,197,94,.25);
        transform: translateY(-1px);
      }
      #heroHospBtn:active { transform: scale(.97); }
    `;
    document.head.appendChild(s);
  }
}

function setupTheme() {
  const btn = document.getElementById('themeBtn');
  if(!btn) return;

  // Determine initial theme: 1) localStorage, 2) system preference
  const saved = localStorage.getItem('hgp_theme');
  const prefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;
  const startLight = saved ? saved === 'light' : !prefersDark;

  if (startLight) {
    document.body.classList.add('light');
    btn.innerHTML = '<i class="fas fa-sun"></i>';
  } else {
    document.body.classList.remove('light');
    btn.innerHTML = '<i class="fas fa-moon"></i>';
  }

  const applyTheme = () => {
    soundClick();
    const isLight = document.body.classList.toggle('light');
    btn.innerHTML = isLight ? '<i class="fas fa-sun"></i>' : '<i class="fas fa-moon"></i>';
    localStorage.setItem('hgp_theme', isLight ? 'light' : 'dark');
    // Update JS-injected sev-badge override colours for the new theme
    updateSevBadgeTheme(isLight);
  };

  btn.onclick = applyTheme;

  // Listen for system preference changes (only when no saved preference)
  window.matchMedia('(prefers-color-scheme: dark)').addEventListener('change', e => {
    if (!localStorage.getItem('hgp_theme')) {
      const wantLight = !e.matches;
      document.body.classList.toggle('light', wantLight);
      btn.innerHTML = wantLight ? '<i class="fas fa-sun"></i>' : '<i class="fas fa-moon"></i>';
      updateSevBadgeTheme(wantLight);
    }
  });
}

function updateSevBadgeTheme(isLight) {
  const el = document.getElementById('sevBadgeOverride');
  if (!el) return;
  if (isLight) {
    el.textContent = `
      .sev-badge {
        display: inline-block; padding: .18rem .6rem; border-radius: 99px;
        font-size: .7rem; font-weight: 700; letter-spacing: .06em; text-transform: capitalize;
      }
      .sev-badge.sev-critical { background: rgba(224,0,43,.10); border: 1px solid rgba(224,0,43,.28); color: #b91c1c; }
      .sev-badge.sev-high { background: rgba(180,83,9,.10); border: 1px solid rgba(180,83,9,.28); color: #92400e; }
      .sev-badge.sev-medium, .sev-badge.sev-moderate { background: rgba(0,168,84,.10); border: 1px solid rgba(0,168,84,.28); color: #065f46; }
      .sev-badge.sev-low { background: rgba(46,125,50,.10); border: 1px solid rgba(46,125,50,.28); color: #1b5e20; }
    `;
  } else {
    el.textContent = `
      .sev-badge {
        display: inline-block; padding: .18rem .6rem; border-radius: 99px;
        font-size: .7rem; font-weight: 700; letter-spacing: .06em; text-transform: capitalize;
      }
      .sev-badge.sev-critical { background: rgba(239,68,68,.15); border: 1px solid rgba(239,68,68,.4); color: #f87171; }
      .sev-badge.sev-high { background: rgba(249,115,22,.14); border: 1px solid rgba(249,115,22,.38); color: #fb923c; }
      .sev-badge.sev-medium, .sev-badge.sev-moderate { background: rgba(234,179,8,.13); border: 1px solid rgba(234,179,8,.38); color: #fbbf24; }
      .sev-badge.sev-low { background: rgba(56,189,248,.12); border: 1px solid rgba(56,189,248,.35); color: #7dd3fc; }
    `;
  }
}

// ==========================================
// ABOUT BUTTON & MODAL
// ==========================================
function injectAboutButton() {
  if (!document.getElementById('aboutBtnStyle')) {
    const s = document.createElement('style');
    s.id = 'aboutBtnStyle';
    s.textContent = `

      /* ═══════════════════════════════════════════
         MIXED PALETTE VARIABLES (Black · Green · Blue)
      ═══════════════════════════════════════════ */
      :root {
        --g0:  #ecfdf5;   /* near-white mint     */
        --g1:  #d1fae5;   /* pale mint           */
        --g2:  #a7f3d0;   /* soft sage           */
        --g3:  #6ee7b7;   /* light aqua-green    */
        --g4:  #34d399;   /* medium emerald      */
        --g5:  #10b981;   /* vivid emerald       */
        --g6:  #059669;   /* deep emerald        */
        --g7:  #047857;   /* forest              */
        --g8:  #065f46;   /* dark forest         */
        --g9:  #064e3b;   /* near-black forest   */
        --gneon:#4ade80;   /* neon lime           */
        --glime:#84cc16;   /* lime yellow-green   */
        --gviv: #22c55e;   /* vivid green         */
        --gsage:#86efac;   /* sage                */
        /* Blues */
        --b1:  #bfdbfe;   /* pale blue           */
        --b2:  #93c5fd;   /* soft blue           */
        --b3:  #60a5fa;   /* sky blue            */
        --b4:  #3b82f6;   /* medium blue         */
        --b5:  #2563eb;   /* vivid blue          */
        --b6:  #1d4ed8;   /* deep blue           */
        --b7:  #1e40af;   /* navy                */
        /* Near-blacks */
        --k1:  #e2e8f0;   /* light slate         */
        --k2:  #94a3b8;   /* mid slate           */
        --k3:  #475569;   /* dark slate          */
        --k4:  #1e293b;   /* near black          */
        --k5:  #0f172a;   /* deepest             */
      }

      /* ─── About Trigger Button ─── */
      #aboutFloatBtn {
        display: inline-flex;
        align-items: center;
        gap: .5rem;
        padding: .52rem 1.6rem;
        border-radius: 99px;
        border: 1px solid rgba(255,255,255,.08);
        background: rgba(18,18,18,.92);
        color: rgba(180,180,180,.7);
        font-size: .84rem;
        font-weight: 600;
        letter-spacing: .06em;
        cursor: pointer;
        text-transform: uppercase;
        transition: background .22s, border-color .22s, color .2s, transform .18s;
      }
      #aboutFloatBtn:hover {
        background: rgba(28,28,28,.96);
        border-color: rgba(255,255,255,.16);
        color: rgba(210,210,210,.85);
        transform: translateY(-1px);
      }
      #aboutFloatBtn:active { transform: scale(.97); }

      #aboutBtnWrap {
        display: flex;
        justify-content: center;
        margin-top: .85rem;
        padding-bottom: .5rem;
      }

      /* ─── Overlay ─── */
      #aboutOverlay {
        display: none;
        position: fixed;
        inset: 0;
        z-index: 2000;
        background: rgba(0,8,4,.88);
        backdrop-filter: blur(14px) saturate(1.4);
        -webkit-backdrop-filter: blur(14px) saturate(1.4);
        align-items: center;
        justify-content: center;
        padding: 1.2rem;
        overflow-y: auto;
      }
      #aboutOverlay.open { display: flex; }

      /* ─── Modal Box ─── */
      #aboutBox {
        position: relative;
        background: linear-gradient(160deg,
          rgba(4,10,20,1)  0%,
          rgba(3,9,5,1)   40%,
          rgba(6,12,28,1) 100%);
        border: 1px solid rgba(59,130,246,.22);
        border-radius: 24px;
        width: 100%;
        max-width: 1100px;
        max-height: 90vh;
        overflow-y: auto;
        overflow-x: hidden;
        padding: 2.6rem 2.4rem 2.2rem;
        box-shadow:
          0 0 0 1px rgba(59,130,246,.08),
          0 12px 80px rgba(0,0,0,.9),
          0 0 120px rgba(29,78,216,.07) inset;
        scrollbar-width: thin;
        scrollbar-color: rgba(59,130,246,.2) transparent;
        animation: aboutDropIn .5s cubic-bezier(.22,.68,0,1.15) forwards;
      }
      @keyframes aboutDropIn {
        from { opacity:0; transform:translateY(-40px) scale(.95); }
        to   { opacity:1; transform:translateY(0)     scale(1);   }
      }

      /* ─── Animated BG orbs ─── */
      .about-orb {
        position: absolute;
        border-radius: 50%;
        filter: blur(60px);
        pointer-events: none;
        opacity: 0;
        animation: orbFloat 8s ease-in-out infinite;
      }
      .about-orb-1 {
        width: 440px; height: 440px;
        top: -100px; left: -80px;
        background: radial-gradient(circle, rgba(6,95,70,.45) 0%, transparent 70%);
        animation-delay: 0s;
        opacity: .55;
      }
      .about-orb-2 {
        width: 365px; height: 365px;
        top: 60px; right: -60px;
        background: radial-gradient(circle, rgba(29,78,216,.45) 0%, transparent 70%);
        animation-delay: -3s;
        opacity: .5;
      }
      .about-orb-3 {
        width: 290px; height: 290px;
        bottom: 40px; left: 30%;
        background: radial-gradient(circle, rgba(37,99,235,.28) 0%, transparent 70%);
        animation-delay: -5.5s;
        opacity: .4;
      }
      @keyframes orbFloat {
        0%,100% { transform: translate(0,0)   scale(1);   }
        33%      { transform: translate(20px,-18px) scale(1.06); }
        66%      { transform: translate(-14px,12px) scale(.96); }
      }

      /* ─── Grid of shimmer specks ─── */
      .about-grid-bg {
        position: absolute;
        inset: 0;
        background-image:
          radial-gradient(circle, rgba(59,130,246,.05) 1px, transparent 1px);
        background-size: 28px 28px;
        pointer-events: none;
        border-radius: inherit;
      }

      /* ─── Close Button ─── */
      #aboutCloseBtn {
        position: absolute;
        top: 1.1rem; right: 1.2rem;
        background: rgba(29,78,216,.25);
        border: 1px solid rgba(59,130,246,.28);
        color: var(--b2);
        width: 34px; height: 34px;
        border-radius: 50%;
        display: flex; align-items: center; justify-content: center;
        cursor: pointer; font-size: .9rem;
        transition: background .2s, color .2s, transform .22s, box-shadow .2s;
        z-index: 10;
        flex-shrink: 0;
      }
      #aboutCloseBtn:hover {
        background: rgba(29,78,216,.55);
        color: var(--b1);
        border-color: rgba(59,130,246,.6);
        box-shadow: 0 0 14px rgba(59,130,246,.35);
        transform: rotate(90deg);
      }

      /* ─── Header ─── */
      .about-header {
        text-align: center;
        margin-bottom: 2rem;
        position: relative;
        z-index: 2;
      }
      .about-badge {
        display: inline-flex; align-items: center; gap: .4rem;
        padding: .28rem 1rem;
        border-radius: 99px;
        background: linear-gradient(135deg, rgba(29,78,216,.6) 0%, rgba(37,99,235,.4) 100%);
        border: 1px solid rgba(59,130,246,.45);
        color: var(--b2);
        font-size: .72rem; font-weight: 800;
        letter-spacing: .14em; text-transform: uppercase;
        margin-bottom: 1.1rem;
        box-shadow: 0 0 16px rgba(37,99,235,.22);
      }
      .about-title {
        font-size: 2.1rem; font-weight: 900;
        background: linear-gradient(135deg,
          var(--k1)  0%,
          var(--g3) 30%,
          var(--b3) 60%,
          var(--g4) 100%);
        -webkit-background-clip: text;
        -webkit-text-fill-color: transparent;
        background-clip: text;
        margin: 0 0 .9rem;
        line-height: 1.15;
        letter-spacing: -.01em;
      }
      .about-desc {
        color: rgba(148,163,184,.75);
        font-size: .92rem; line-height: 1.75;
        max-width: 580px; margin: 0 auto;
      }
      .about-desc strong { color: var(--b2); font-weight: 700; }

      /* ─── Feature Chips ─── */
      .about-features {
        display: flex; gap: .6rem; flex-wrap: wrap;
        justify-content: center;
        margin: 1.5rem 0 0;
      }
      .about-feat-chip {
        display: inline-flex; align-items: center; gap: .35rem;
        padding: .32rem .9rem; border-radius: 99px;
        font-size: .76rem; font-weight: 700; letter-spacing: .03em;
        transition: transform .18s, box-shadow .18s;
      }
      .about-feat-chip:hover { transform: translateY(-2px); }
      /* all chips — light lavender */
      .about-feat-chip.c1 { background:rgba(167,139,250,.14); border:1px solid rgba(167,139,250,.38); color:#c4b5fd; }
      .about-feat-chip.c2 { background:rgba(167,139,250,.14); border:1px solid rgba(167,139,250,.38); color:#c4b5fd; }
      .about-feat-chip.c3 { background:rgba(167,139,250,.14); border:1px solid rgba(167,139,250,.38); color:#c4b5fd; }
      .about-feat-chip.c4 { background:rgba(167,139,250,.14); border:1px solid rgba(167,139,250,.38); color:#c4b5fd; }
      .about-feat-chip.c5 { background:rgba(167,139,250,.14); border:1px solid rgba(167,139,250,.38); color:#c4b5fd; }
      .about-feat-chip.c1:hover { box-shadow:0 0 16px rgba(167,139,250,.3); }
      .about-feat-chip.c2:hover { box-shadow:0 0 16px rgba(167,139,250,.3); }
      .about-feat-chip.c3:hover { box-shadow:0 0 16px rgba(167,139,250,.3); }
      .about-feat-chip.c4:hover { box-shadow:0 0 16px rgba(167,139,250,.3); }
      .about-feat-chip.c5:hover { box-shadow:0 0 16px rgba(167,139,250,.3); }

      /* ─── Divider ─── */
      .about-divider {
        height: 1px;
        background: linear-gradient(90deg,
          transparent,
          rgba(59,130,246,.18) 15%,
          rgba(52,211,153,.4) 50%,
          rgba(59,130,246,.18) 85%,
          transparent);
        margin: 2rem 0;
        position: relative; z-index: 2;
      }

      /* ─── Meet heading ─── */
      .meet-heading {
        text-align: center; margin-bottom: 1.8rem;
        position: relative; z-index: 2;
      }
      .meet-heading h3 {
        font-size: 1.3rem; font-weight: 900;
        background: linear-gradient(135deg, var(--k1) 0%, var(--g3) 45%, var(--b3) 100%);
        -webkit-background-clip: text;
        -webkit-text-fill-color: transparent;
        background-clip: text;
        margin: 0 0 .3rem;
        letter-spacing: .01em;
      }
      .meet-heading p { color: rgba(96,165,250,.45); font-size: .82rem; margin: 0; }

      /* ─── Creator Grid ─── */
      .creator-grid {
        display: grid;
        grid-template-columns: repeat(4, 1fr);
        gap: 1.2rem;
        position: relative; z-index: 2;
      }

      /* ─── Drop-in keyframe (each card uses a unique delay set by inline style) ─── */
      @keyframes cardDrop {
        0%   { opacity:0; transform: translateY(-60px) scale(.9) rotateX(12deg); }
        70%  { transform: translateY(6px) scale(1.01) rotateX(-2deg); }
        100% { opacity:1; transform: translateY(0) scale(1) rotateX(0deg); }
      }
      .creator-card {
        opacity: 0;  /* start hidden; JS triggers animation when modal opens */
      }
      .creator-card.dropped {
        animation: cardDrop .32s cubic-bezier(.22,.68,0,1.2) forwards;
      }

      /* all cards: light-green outer border glow, light-blue inner avatar glow */
      .creator-card[data-shade="1"] { --card-glow: rgba(134,239,172,.55); --card-border: rgba(134,239,172,.45); --card-hi: #86efac; --avatar-glow: rgba(147,197,253,.6); }
      .creator-card[data-shade="2"] { --card-glow: rgba(134,239,172,.55); --card-border: rgba(134,239,172,.45); --card-hi: #86efac; --avatar-glow: rgba(147,197,253,.6); }
      .creator-card[data-shade="3"] { --card-glow: rgba(134,239,172,.55); --card-border: rgba(134,239,172,.45); --card-hi: #86efac; --avatar-glow: rgba(147,197,253,.6); }
      .creator-card[data-shade="4"] { --card-glow: rgba(134,239,172,.55); --card-border: rgba(134,239,172,.45); --card-hi: #86efac; --avatar-glow: rgba(147,197,253,.6); }

      .creator-card {
        background: linear-gradient(145deg,
          rgba(5,8,20,.72) 0%,
          rgba(3,7,15,.68) 100%);
        backdrop-filter: blur(18px) saturate(1.6);
        -webkit-backdrop-filter: blur(18px) saturate(1.6);
        border: 1px solid var(--card-border);
        border-radius: 18px;
        padding: 1.6rem 1.1rem 1.3rem;
        display: flex; flex-direction: column;
        align-items: center; gap: .65rem;
        position: relative; overflow: hidden;
        transition: border-color .25s, box-shadow .3s, transform .22s, backdrop-filter .3s;
        perspective: 600px;
      }
      .creator-card:hover {
        backdrop-filter: blur(24px) saturate(2);
        -webkit-backdrop-filter: blur(24px) saturate(2);
      }
      /* inner top-edge glow line */
      .creator-card::before {
        content:'';
        position:absolute; top:0; left:10%; right:10%; height:1px;
        background: linear-gradient(90deg, transparent, var(--card-hi), transparent);
        opacity: .7;
      }
      /* radial shimmer */
      .creator-card::after {
        content:'';
        position:absolute; inset:0;
        background: radial-gradient(ellipse at 50% -10%, var(--card-glow) 0%, transparent 60%);
        opacity:.18; pointer-events:none;
        transition: opacity .3s;
      }
      .creator-card:hover {
        border-color: var(--card-hi);
        box-shadow: 0 8px 40px var(--card-glow),
                    0 0 0 1px var(--card-border);
        transform: translateY(-5px) scale(1.02);
      }
      .creator-card:hover::after { opacity:.32; }

      /* ─── Avatar ─── */
      .creator-avatar {
        width: 150px; height: 150px;
        border-radius: 50%;
        border: 2px solid rgba(134,239,172,.55);
        box-shadow: 0 0 22px var(--avatar-glow, rgba(147,197,253,.55)), inset 0 0 18px rgba(147,197,253,.18);
        background: radial-gradient(circle at 40% 35%, rgba(147,197,253,.18) 0%, rgba(3,7,15,.95) 100%);
        display: flex; align-items: center; justify-content: center;
        font-size: 3.6rem;
        color: #93c5fd;
        flex-shrink: 0; overflow: hidden;
        position: relative; z-index: 1;
        transition: box-shadow .25s, border-color .25s;
      }
      .creator-card:hover .creator-avatar {
        box-shadow: 0 0 36px rgba(147,197,253,.7), 0 0 64px rgba(147,197,253,.35), inset 0 0 24px rgba(147,197,253,.25);
        border-color: #93c5fd;
      }

      /* pulse ring on avatar */
      .creator-avatar::after {
        content:'';
        position:absolute; inset:-5px;
        border-radius: 50%;
        border: 1px solid #93c5fd;
        opacity:0;
        animation: avatarPulse 2.8s ease-in-out infinite;
        animation-play-state: paused;
      }
      .creator-card:hover .creator-avatar::after { animation-play-state: running; }
      @keyframes avatarPulse {
        0%,100% { opacity:0; transform:scale(1); }
        50%      { opacity:.5; transform:scale(1.15); }
      }

      /* ─── Creator Name ─── */
      .creator-name {
        font-size: .92rem; font-weight: 800;
        color: var(--g0);
        text-align: center; line-height: 1.25; margin: 0;
        letter-spacing: .01em;
        position: relative; z-index: 1;
      }

      /* ─── Social Links ─── */
      .creator-links {
        display: flex; gap: .5rem;
        margin-top: .15rem;
        position: relative; z-index: 1;
      }
      .creator-link {
        display: inline-flex; align-items: center; justify-content: center;
        width: 34px; height: 34px; border-radius: 50%;
        font-size: .85rem; font-weight: 700;
        text-decoration: none;
        transition: background .2s, box-shadow .2s, transform .15s, color .2s;
        cursor: pointer;
      }
      .creator-link.linkedin {
        background: rgba(10,102,194,.25);
        border: 1px solid rgba(10,102,194,.45);
        color: #7ab8f5;
      }
      .creator-link.linkedin:hover {
        background: rgba(10,102,194,.5);
        box-shadow: 0 0 14px rgba(10,102,194,.35);
        color: #bdd8f7; transform: translateY(-1px);
      }
      .creator-link.github {
        background: rgba(30,30,40,.7);
        border: 1px solid rgba(148,163,184,.22);
        color: var(--k2);
      }
      .creator-link.github:hover {
        background: rgba(50,50,65,.8);
        box-shadow: 0 0 14px rgba(148,163,184,.18);
        color: var(--k1); transform: translateY(-1px);
      }
      .creator-link i { font-size: .9rem; }

      /* ─── Footer tagline ─── */
      .about-footer-tag {
        text-align: center;
        margin-top: 2.2rem;
        color: rgba(96,165,250,.32);
        font-size: .76rem; letter-spacing: .06em;
        position: relative; z-index: 2;
      }
      .about-footer-tag span { color: var(--b3); }

      /* ─── Responsive ─── */
      @media (max-width: 540px) {
        #aboutBox { padding: 1.8rem 1rem 1.5rem; }
        .about-title { font-size: 1.55rem; }
        .creator-grid { grid-template-columns: repeat(2, 1fr); gap: .85rem; }
        .creator-links { flex-direction: column; gap: .38rem; }
        .creator-link { justify-content: center; }
        .creator-name { font-size: .83rem; }
      }

      /* ─── Light Mode overrides ─── */
      .light #aboutOverlay {
        background: rgba(15,23,42,.55);
      }
      .light #aboutBox {
        background: linear-gradient(160deg, #f8fafc 0%, #f0fdf4 40%, #eff6ff 100%);
        border-color: rgba(59,130,246,.18);
        box-shadow: 0 0 0 1px rgba(59,130,246,.06), 0 8px 50px rgba(0,0,0,.14);
      }
      .light .about-grid-bg {
        background-image: radial-gradient(circle, rgba(59,130,246,.07) 1px, transparent 1px);
      }
      .light .about-orb-1 { background: radial-gradient(circle, rgba(16,185,129,.2) 0%, transparent 70%); opacity: .35; }
      .light .about-orb-2 { background: radial-gradient(circle, rgba(59,130,246,.2) 0%, transparent 70%); opacity: .3; }
      .light .about-orb-3 { background: radial-gradient(circle, rgba(37,99,235,.15) 0%, transparent 70%); opacity: .25; }
      .light .about-title { color: #0f172a; }
      .light .about-desc { color: #334155; }
      .light .about-desc strong { color: #0f172a; }
      .light .about-badge { background: linear-gradient(135deg, rgba(16,185,129,.15), rgba(59,130,246,.10)); border-color: rgba(16,185,129,.30); color: #065f46; }
      .light .about-divider { border-color: rgba(0,0,0,.08); }
      .light .meet-heading h3 { color: #1e293b; }
      .light .meet-heading p { color: #475569; }
      .light .creator-card { background: linear-gradient(135deg, rgba(255,255,255,.70), rgba(240,253,244,.65)); backdrop-filter: blur(18px) saturate(1.8); -webkit-backdrop-filter: blur(18px) saturate(1.8); border-color: rgba(16,185,129,.22); }
      .light .creator-card:hover { border-color: rgba(16,185,129,.45); box-shadow: 0 8px 30px rgba(16,185,129,.12); }
      .light .creator-name { color: #0f172a; }
      .light .creator-avatar { background: linear-gradient(135deg, rgba(16,185,129,.15), rgba(59,130,246,.10)); border-color: rgba(16,185,129,.30); color: #065f46; }
      .light .creator-link.linkedin { background: rgba(10,102,194,.10); border-color: rgba(10,102,194,.25); color: #0a66c2; }
      .light .creator-link.github   { background: rgba(36,41,47,.08); border-color: rgba(36,41,47,.20); color: #24292f; }
      .light .about-feat-chip { color: #1e293b; }
      .light .about-footer-tag { color: rgba(100,116,139,.55); }
      .light #aboutCloseBtn { background: rgba(16,185,129,.12); border-color: rgba(16,185,129,.25); color: #065f46; }
      .light #aboutCloseBtn:hover { background: rgba(16,185,129,.22); border-color: rgba(16,185,129,.45); color: #047857; box-shadow: 0 0 12px rgba(16,185,129,.20); }
      .light #aboutFloatBtn { background: rgba(248,250,252,.96); border-color: rgba(0,0,0,.10); color: #475569; }
      .light #aboutFloatBtn:hover { background: #ffffff; border-color: rgba(0,0,0,.15); color: #0f172a; }
    `;
    document.head.appendChild(s);
  }

  const CREATOR_PHOTOS = [
  "data:image/jpeg;base64,",
  "data:image/jpeg;base64,",
  "data:image/jpeg;base64,",
  "data:image/jpeg;base64,"
]

  // ── Creator data ──
  const creators = [
    { name:'Kinjal Pramanik', shade:1,
      linkedin:'https://www.linkedin.com/in/kinjal-pramanik-5b95453b6',
      github:'https://github.com/KinjalPramanik06' },
    { name:'Ankurak Roy', shade:2,
      linkedin:'https://www.linkedin.com/in/ankurak-roy-17350b3b6',
      github:'https://github.com/ANKURAKROY' },
    { name:'Souvick Saha', shade:3,
      linkedin:'https://www.linkedin.com/in/souvick-saha-a8a98b318',
      github:'https://github.com/05souvicksaha' },
    { name:'Aryan Chowdhury', shade:4,
      linkedin:'https://www.linkedin.com/in/aryan-chowdhury-9b04083b7',
      github:'https://github.com/07aryanchowdhury' }
  ];

  const icons = ['fa-seedling','fa-leaf','fa-tree','fa-spa'];

  const creatorCardsHTML = creators.map((c, i) => `
    <div class="creator-card" data-shade="${c.shade}" data-idx="${i}">
      <div class="creator-avatar">
        <img src="${CREATOR_PHOTOS[i]}" alt="${c.name}" style="width:100%;height:100%;object-fit:cover;border-radius:50%;">
      </div>
      <p class="creator-name">${c.name}</p>
      <div class="creator-links">
        <a class="creator-link linkedin" href="${c.linkedin}" target="_blank" rel="noopener noreferrer" title="LinkedIn">
          <i class="fab fa-linkedin-in"></i>
        </a>
        <a class="creator-link github" href="${c.github}" target="_blank" rel="noopener noreferrer" title="GitHub">
          <i class="fab fa-github"></i>
        </a>
      </div>
    </div>
  `).join('');

  // ── Build modal HTML ──
  const overlay = document.createElement('div');
  overlay.id = 'aboutOverlay';
  overlay.innerHTML = `
    <div id="aboutBox" role="dialog" aria-modal="true" aria-labelledby="aboutDialogTitle">

      <!-- animated bg elements -->
      <div class="about-grid-bg"></div>
      <div class="about-orb about-orb-1"></div>
      <div class="about-orb about-orb-2"></div>
      <div class="about-orb about-orb-3"></div>

      <button id="aboutCloseBtn" aria-label="Close about dialog"><i class="fas fa-times"></i></button>

      <div class="about-header">
        <div class="about-badge"><i class="fas fa-shield-heart"></i>&nbsp;HealthGuard Pro</div>
        <h2 class="about-title" id="aboutDialogTitle">About This Platform</h2>
        <p class="about-desc">
          <strong>HealthGuard Pro</strong> is a comprehensive emergency first-aid reference platform built to deliver
          step-by-step treatment guidance across <strong>20+ medical categories</strong> — for bystanders,
          students, and first responders when every second counts.
        </p>
        <div class="about-features">
          <span class="about-feat-chip c1"><i class="fas fa-heart-pulse"></i> 20+ Categories</span>
          <span class="about-feat-chip c2"><i class="fas fa-robot"></i> AI Assistant</span>
          <span class="about-feat-chip c3"><i class="fas fa-hospital-user"></i> Hospitals</span>
          <span class="about-feat-chip c4"><i class="fas fa-layer-group"></i> Flashcards</span>
          <span class="about-feat-chip c5"><i class="fas fa-bolt"></i> Instant Search</span>
        </div>
      </div>

      <div class="about-divider"></div>

      <div class="meet-heading">
        <h3><i class="fas fa-users" style="margin-right:.45rem;"></i>Meet the Creators</h3>
        <p>The minds that built HealthGuard Pro</p>
      </div>

      <div class="creator-grid">
        ${creatorCardsHTML}
      </div>

      <p class="about-footer-tag">
        Made with Phantom Legion &nbsp;·&nbsp; HealthGuard Pro &copy; ${new Date().getFullYear()}
      </p>
    </div>
  `;
  document.body.appendChild(overlay);

  // ── Trigger staggered drop animations when modal opens ──
  const triggerCardDrops = () => {
    const cards = overlay.querySelectorAll('.creator-card');
    cards.forEach(card => {
      card.classList.remove('dropped');
      card.style.animationDelay = '';
      // force reflow so the removed class takes effect
      void card.offsetWidth;
    });
    cards.forEach((card, i) => {
      const delay = 80 + i * 70;  // 80ms, 150ms, 220ms, 290ms
      card.style.animationDelay = delay + 'ms';
      card.classList.add('dropped');
    });
  };

  // ── About trigger button ──
  const btn = document.createElement('button');
  btn.id = 'aboutFloatBtn';
  btn.setAttribute('aria-haspopup', 'dialog');
  btn.innerHTML = '<i class="fas fa-circle-info"></i>&nbsp;About';

  const wrap = document.createElement('div');
  wrap.id = 'aboutBtnWrap';
  wrap.appendChild(btn);

  // ── Smart footer finder ──
  const footerEl = (() => {
    const semantic = document.querySelector('footer');
    if (semantic) return semantic;
    const allEls = Array.from(document.querySelectorAll('div, p, section, aside'));
    const match = allEls.find(el =>
      /HealthGuard\s*Pro/i.test(el.textContent) &&
      /(\u00A9|©|&copy;|2026)/i.test(el.textContent) &&
      el.querySelectorAll('div, section').length === 0
    );
    if (match) return match.closest('div, section, footer') || match;
    return (
      document.getElementById('footer') ||
      document.querySelector('.footer, .site-footer, .page-footer, [class*="footer"]')
    );
  })();

  if (footerEl) footerEl.insertAdjacentElement('afterend', wrap);
  else document.body.appendChild(wrap);

  // ── Wire interactions ──
  const openAbout = () => {
    overlay.classList.add('open');
    document.body.style.overflow = 'hidden';
    triggerCardDrops();
  };
  const closeAbout = () => {
    overlay.classList.remove('open');
    document.body.style.overflow = '';
  };

  btn.addEventListener('click', openAbout);
  document.getElementById('aboutCloseBtn').addEventListener('click', closeAbout);
  overlay.addEventListener('click', e => { if (e.target === overlay) closeAbout(); });
  document.addEventListener('keydown', e => {
    if (e.key === 'Escape' && overlay.classList.contains('open')) closeAbout();
  });
}

// ==========================================
// INITIALIZATION
// ==========================================
window.addEventListener('DOMContentLoaded', () => {
  try {
    // ── Override severity badge colours ──
    if (!document.getElementById('sevBadgeOverride')) {
      const _s = document.createElement('style');
      _s.id = 'sevBadgeOverride';
      _s.textContent = `
        .sev-badge {
          display: inline-block;
          padding: .18rem .6rem;
          border-radius: 99px;
          font-size: .7rem;
          font-weight: 700;
          letter-spacing: .06em;
          text-transform: capitalize;
        }
        .sev-badge.sev-critical {
          background: rgba(239,68,68,.15);
          border: 1px solid rgba(239,68,68,.4);
          color: #f87171;
        }
        .sev-badge.sev-high {
          background: rgba(249,115,22,.14);
          border: 1px solid rgba(249,115,22,.38);
          color: #fb923c;
        }
        .sev-badge.sev-medium, .sev-badge.sev-moderate {
          background: rgba(234,179,8,.13);
          border: 1px solid rgba(234,179,8,.38);
          color: #fbbf24;
        }
        .sev-badge.sev-low {
          background: rgba(56,189,248,.12);
          border: 1px solid rgba(56,189,248,.35);
          color: #7dd3fc;
        }
      `;
      document.head.appendChild(_s);
    }

    renderCategories();
    renderFilters();
    renderTreatments();
    renderFlashcards();
    setupTheme();
    // Apply correct sev-badge colours for current theme after setupTheme runs
    updateSevBadgeTheme(document.body.classList.contains('light'));
    injectHospitalButton();
    injectAboutButton();

    // ── Remove any standalone hospital section at the bottom of the page ──
    const _removeHospitalSections = () => {
      // 1. Selector-based removal
      const hospitalSectionSelectors = [
        '#hospitals', '#local-hospitals', '#localHospitals', '#hospitalSection',
        '#localHospitalSection', '#kolkataHospitals', '#nearbyHospitals',
        '.hospitals-section', '.local-hospitals', '.hospital-section',
        '.nearby-hospitals', '.kolkata-hospitals',
        '[id*="hospital" i]:not(#hospModal):not(#hospModalBox):not(#hospModalHead):not(#hospModalBody):not(#heroHospBtn)',
        '[class*="hospital" i]:not([id*="hospModal" i]):not([id*="heroHosp" i])',
        'section[id*="hosp" i]', 'section[class*="hosp" i]'
      ];
      hospitalSectionSelectors.forEach(sel => {
        try {
          document.querySelectorAll(sel).forEach(el => {
            if (!el.closest('#hospModal') && !el.id.includes('hospModal')) el.remove();
          });
        } catch(e) {}
      });

      // 2. Text-content-based removal — catch any container that lists Kolkata hospitals
      const containers = Array.from(document.querySelectorAll('body > *, main > *, #app > *, #root > *'));
      containers.forEach(el => {
        if (el.id === 'hospModal' || el.id === 'aboutOverlay' || el.id === 'aboutBtnWrap') return;
        const txt = el.textContent || '';
        // If the block mentions multiple hospital names + Kolkata it's the local hospitals section
        const hospitalKeywords = ['SSKM', 'SSKM Hospital', 'Apollo Gleneagles', 'Fortis Hospital',
          'Peerless Hospital', 'RG Kar', 'Belle Vue', 'Medica Superspecialty', 'Rabindranath Tagore'];
        const matchCount = hospitalKeywords.filter(k => txt.includes(k)).length;
        if (matchCount >= 2) el.remove();
      });
    };
    _removeHospitalSections();

    // Also watch for any late-injected hospital sections (e.g. from async scripts)
    new MutationObserver((mutations) => {
      mutations.forEach(m => {
        m.addedNodes.forEach(node => {
          if (node.nodeType !== 1) return;
          const txt = node.textContent || '';
          const id  = (node.id || '').toLowerCase();
          const cls = (node.className || '').toLowerCase();
          if ((id.includes('hospital') || cls.includes('hospital') || txt.includes('Kolkata') && txt.includes('Emergency')) &&
              !id.includes('hospmodal') && !id.includes('herohosp')) {
            node.remove();
          }
        });
      });
    }).observe(document.body, { childList: true, subtree: false });

    // Animate hero stats counters
    const totalCats = Object.keys(CATS).length;
    animateCounter('counter1', DB.length, 1600);
    animateCounter('counter2', totalCats, 1400);
    animateCounter('counter3', DB.reduce((n, t) => n + t.steps.length, 0), 1800);
    
    setTimeout(() => {
      if(!chatOpen) {
        document.getElementById('chatNotif').style.display = 'block';
        toast('HealthGuard Pro is ready to assist!', 'info', 4000);
      }
    }, 5000);

    document.addEventListener('click', e => {
      if(!e.target.closest('.search-wrap')) {
         const drop = document.getElementById('searchDrop');
         if(drop) {
           drop.style.transition = 'opacity .18s ease, transform .18s ease';
           drop.style.opacity = '0';
           drop.style.transform = 'translateY(-6px)';
           setTimeout(() => { drop.style.display = 'none'; drop.style.opacity = ''; drop.style.transform = ''; }, 180);
         }
      }
    });

    document.querySelectorAll('.overlay').forEach(o => {
      o.addEventListener('click', e => { if(e.target === o) closeModal(o.id); });
    });

    // ── Global ripple effect on buttons ──
    document.addEventListener('click', e => {
      const btn = e.target.closest('button, .tcard, .cat-card, .fc-card');
      if (!btn) return;
      const ripple = document.createElement('span');
      const rect = btn.getBoundingClientRect();
      const size = Math.max(rect.width, rect.height) * 1.6;
      ripple.style.cssText = `
        position:absolute; border-radius:50%; pointer-events:none;
        width:${size}px; height:${size}px;
        left:${e.clientX - rect.left - size/2}px;
        top:${e.clientY - rect.top - size/2}px;
        background:rgba(255,255,255,0.18);
        transform:scale(0); opacity:1;
        transition:transform .5s cubic-bezier(.22,.68,0,1.2), opacity .5s ease;
        z-index:99;
      `;
      const prevPos = btn.style.position;
      if (!prevPos || prevPos === 'static') btn.style.position = 'relative';
      btn.style.overflow = btn.style.overflow || 'hidden';
      btn.appendChild(ripple);
      requestAnimationFrame(() => {
        ripple.style.transform = 'scale(1)';
        ripple.style.opacity = '0';
      });
      setTimeout(() => { ripple.remove(); if (!prevPos || prevPos === 'static') btn.style.position = prevPos; }, 520);
    });

    // ── Stagger-animate modal step items when modal opens ──
    const treatModal = document.getElementById('treatmentModal');
    if (treatModal) {
      const obs = new MutationObserver(() => {
        if (treatModal.classList.contains('open')) {
          const items = treatModal.querySelectorAll('.step-item, .donot-item, .tag');
          items.forEach((el, i) => {
            el.style.opacity = '0';
            el.style.transform = 'translateY(14px)';
            el.style.transition = 'none';
            setTimeout(() => {
              el.style.transition = `opacity .3s ease, transform .32s cubic-bezier(.22,.68,0,1.2)`;
              el.style.opacity = '1';
              el.style.transform = 'translateY(0)';
            }, 180 + i * 45);
          });
        }
      });
      obs.observe(treatModal, { attributes: true, attributeFilter: ['class'] });
    }
  } catch(err) {
    console.error("Initialization Error: ", err);
  }
});